function CalcAcq(){
  const[price,sP]=useState("12500");const[own,sO]=useState("1");const[area,sA]=useState("84");const[reg,sR]=useState("spec");const[isFirst,sFirst]=useState("no");const[isTempTwo,sTT]=useState("no");
  const today=new Date();const firstHomeBenefitEnd=new Date('2028-12-31');const isFirstHomeBenefit=today<firstHomeBenefitEnd;
  const pW=tW(price);let r=0.01;const n=parseInt(own),isR=reg!=="non";
  if(n===2&&isTempTwo==="yes"){r=pW<=6e8?0.01:pW<=9e8?Math.max(0.01,(pW*2/3e8-3)/100):0.03;}
  else if(n===1||(n===2&&!isR)){r=pW<=6e8?0.01:pW<=9e8?Math.max(0.01,(pW*2/3e8-3)/100):0.03;}else if(n===2&&isR){r=0.08;}else if(n>=3){r=isR?0.12:0.08;}
  r=Math.max(0.01,Math.min(r,0.12));const ac=pW*r,ed=ac*.1;const isHeavy=r>=0.08;const fm=isHeavy?pW*.002:(parseInt(area)>85&&pW>6e8?pW*.002:0);const st=pW>1e9?350000:pW>5e8?150000:70000;const firstDed=isFirst==="yes"&&n===1&&isFirstHomeBenefit?Math.min(ac,2000000):0;const total=ac+ed+fm+st-firstDed;
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}>
    <div>
      <h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏢 취득세 시뮬레이션</h3>
      <Slider label="매매가격" value={price} onChange={sP} min={1000} max={500000} step={500}/>
      <Radio label="보유 주택 수" value={own} onChange={sO} options={[{value:"1",label:"1주택 (무주택자의 첫 주택 취득)"},{value:"2",label:"2주택 (1주택 보유 중 추가 취득)"},{value:"3",label:"3주택 이상"}]}/>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
        <Inp label="전용면적 (㎡)" value={area} onChange={sA}/><Sel label="지역 구분" value={reg} onChange={sR} options={[{value:"spec",label:"투기과열지구 (서울 등)"},{value:"adj",label:"조정대상지역"},{value:"non",label:"비규제지역"}]}/>
      </div>
      <Tog label="생애최초 구입자" value={isFirst} onChange={sFirst} options={[{value:"no",label:"아니오"},{value:"yes",label:"예 (최대 200만원 감면)"}]}/>
      {isFirst==="yes"&&!isFirstHomeBenefit&&<div style={{padding:"12px 16px",background:"#FFEBE6",border:"1px solid #FFBDAD",borderRadius:10,fontSize:13,color:"#DE350B",marginTop:8,marginBottom:12,lineHeight:1.6}}>⚠️ 생애최초 취득세 감면 혜택이 종료되었습니다 (2028.12.31 만료).</div>}
      {n===2&&<Tog label="일시적 2주택 (이사 목적)" value={isTempTwo} onChange={sTT} options={[{value:"no",label:"아니오"},{value:"yes",label:"예 (3년 내 처분 예정)"}]}/>}
    </div>
    <RP title="예상 취득 비용" total={total} sub={"세율 "+fP(r*100)+" 적용"}
      items={[{l:"취득세 ("+fP(r*100)+")",v:fW(ac)},{l:"지방교육세",v:fW(ed)},{l:"농어촌특별세",v:fm>0?fW(fm):"해당없음"},{l:"인지세·증지대",v:fW(st)},{l:"생애최초 감면",v:firstDed>0?"-"+fW(firstDed):"해당없음"}].concat(isTempTwo==="yes"?[{l:"일시적 2주택 특례",v:"1주택 세율 적용"}]:[])}/>
  </div>);
}

function CalcTrans(){
  const[bp,sBp]=useState("");const[sp,sSp]=useState("");const[ex,sEx]=useState("");const[hy,sHy]=useState("5");const[ly,sLy]=useState("3");const[hm,sHm]=useState("1");const[wasAdj,sWA]=useState("no");const[sellAdj,sSA]=useState("no");
  const b=tW(bp),s=tW(sp),e=tW(ex),g=s-b-e;const hv=parseInt(hy),adjLv=Math.min(parseInt(ly),parseInt(hy)),nv=parseInt(hm);
  const today=new Date();const moratoriumEnd=new Date('2026-05-10');const isMoratorium=today<moratoriumEnd;const isSellAdj=sellAdj==="yes";
  let surcharge=0;if(!isMoratorium&&isSellAdj&&nv>=2){surcharge=nv>=3?0.30:0.20;}
  const needResidence=wasAdj==="yes";const is1h=nv===1&&hv>=2&&(!needResidence||adjLv>=2),overLimit=s>12e8;let exempt=is1h&&!overLimit,ltD=0;
  if(!exempt){if(nv===1&&hv>=3)ltD=Math.min(Math.min(hv,15)*.04+Math.min(adjLv,10)*.04,.80);else if(nv>1&&hv>=3)ltD=Math.min(hv*.02,.30);}
  if(surcharge>0)ltD=0;
  let taxableGain=g;if(is1h&&overLimit){taxableGain=g*(s-12e8)/s;}
  const tg=exempt?0:Math.max(0,taxableGain*(1-ltD)-2500000);const baseTax=pTx(tg,IB);const surTax=surcharge>0?Math.round(tg*surcharge):0;const tx=baseTax+surTax;const loc=tx*.1;
  const baseItems=exempt?[{l:"양도차익",v:fW(g)},{l:"비과세 요건",v:"1주택, 2년↑, 12억↓"}]:[{l:"양도차익",v:fW(g)},{l:is1h&&overLimit?"과세 대상 차익 (12억 초과분)":"양도차익",v:is1h&&overLimit?fW(taxableGain):fW(g)},{l:"장기보유특별공제",v:surcharge>0?"중과 배제":fP(ltD*100)},{l:"기본공제",v:"-₩250만"},{l:"과세표준",v:fW(tg)},{l:"기본세율 산출세액",v:fW(baseTax)}];
  const surItems=surcharge>0?[{l:"다주택 중과세율",v:"+"+(surcharge*100)+"%p (2026.5.10~ 시행)"},{l:"중과 가산세액",v:fW(surTax)}]:[];
  const finalItems=exempt?baseItems:[...baseItems,...surItems,{l:"양도소득세 합계",v:fW(tx)},{l:"지방소득세 (10%)",v:fW(loc)}];
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}>
    <div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>📊 양도소득세 시뮬레이션</h3>
      <Inp label="취득가액 (매입가)" value={bp} onChange={sBp} suffix="만원" placeholder="예: 50000"/>
      <Inp label="양도가액 (매도가)" value={sp} onChange={sSp} suffix="만원" placeholder="예: 80000"/>
      <Inp label="필요경비 (취득세·중개비·수리비 등)" value={ex} onChange={sEx} suffix="만원" placeholder="예: 500"/>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
        <Sel label="보유기간" value={hy} onChange={sHy} options={Array.from({length:20},(_,i)=>({value:String(i+1),label:(i+1)+"년"}))}/><Sel label="거주기간" value={ly} onChange={sLy} options={Array.from({length:16},(_,i)=>({value:String(i),label:i+"년"}))}/><Sel label="주택 수" value={hm} onChange={sHm} options={[{value:"1",label:"1주택"},{value:"2",label:"2주택"},{value:"3",label:"3주택+"}]}/>
      </div>
      <Tog label="취득 당시 조정대상지역" value={wasAdj} onChange={sWA} options={[{value:"no",label:"아니오"},{value:"yes",label:"예 (2년 거주 필수)"}]}/>
      {nv>=2&&<Tog label="매도 시점 조정대상지역" value={sellAdj} onChange={sSA} options={[{value:"no",label:"아니오"},{value:"yes",label:"예 (다주택 중과 대상)"}]}/>}
      {isMoratorium&&nv>=2&&isSellAdj&&<div style={{padding:"12px 16px",background:"#FFF8E1",border:"1px solid #FFE082",borderRadius:10,fontSize:13,color:"#F57F17",marginTop:12,lineHeight:1.6}}>⚠️ 현재 다주택 중과가 유예 중입니다 (2026.5.9까지). 유예 종료 후 조정대상지역 {nv}주택은 +{nv>=3?30:20}%p 중과됩니다. 유예 기간 내 매도를 고려하세요.</div>}
      {!isMoratorium&&surcharge>0&&<div style={{padding:"12px 16px",background:"#FFEBE6",border:"1px solid #FFBDAD",borderRadius:10,fontSize:13,color:"#DE350B",marginTop:12,lineHeight:1.6}}>⚠️ 다주택 중과 적용 중: 조정대상지역 {nv}주택 +{surcharge*100}%p, 장특공제 배제</div>}
    </div>
    {g>0?<RP title={exempt?"비과세 적용":is1h&&overLimit?"12억 초과분 과세":surcharge>0?"다주택 중과 양도세":"양도소득세"} total={exempt?0:tx+loc} sub={exempt?"1세대 1주택 비과세":surcharge>0?"기본세율 + "+(surcharge*100)+"%p 중과":is1h&&overLimit?"12억 초과분만 과세 · 장특공제 "+fP(ltD*100):"장특공제 "+fP(ltD*100)} items={finalItems}/>
    :<Empty icon="📊"/>}
  </div>);
}

function CalcCompre(){const[h,sH]=useState("1");const[p,sP]=useState("");const[age,sAge]=useState("0");const[hold,sHold]=useState("0");
  const pp=tW(p),n=parseInt(h),d=n===1?12e8:9e8,tb=Math.max(0,(pp-d)*.6);const C1=[[3e8,.005],[6e8,.007],[12e8,.01],[25e8,.013],[50e8,.02],[94e8,.022],[Infinity,.027]];const CX=[[3e8,.005],[6e8,.007],[12e8,.01],[25e8,.02],[50e8,.03],[94e8,.04],[Infinity,.05]];const ct=pTx(tb,n<=2?C1:CX);
  const ageV=parseInt(age),holdV=parseInt(hold);let ageCredit=0,holdCredit=0;
  if(n===1){if(ageV>=70)ageCredit=.4;else if(ageV>=65)ageCredit=.3;else if(ageV>=60)ageCredit=.2;if(holdV>=15)holdCredit=.5;else if(holdV>=10)holdCredit=.4;else if(holdV>=5)holdCredit=.2;}
  const combinedCredit=Math.min(ageCredit+holdCredit,.8);const creditAmount=Math.round(ct*combinedCredit);const finalCt=ct-creditAmount;const fm=Math.round(finalCt*.2);
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏘️ 종합부동산세</h3>
    <Sel label="주택 수" value={h} onChange={sH} options={[{value:"1",label:"1주택"},{value:"2",label:"2주택"},{value:"3",label:"3주택 이상 (중과)"}]}/>
    <Inp label="주택 공시가격 합계" value={p} onChange={sP} suffix="만원" placeholder="예: 150000" note={"공제금액: "+(n===1?"12억원":"9억원")}/>
    {n===1&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}><Sel label="만 나이 (1주택자)" value={age} onChange={sAge} options={[{value:"0",label:"60세 미만"},{value:"60",label:"60~64세 (20%)"},{value:"65",label:"65~69세 (30%)"},{value:"70",label:"70세 이상 (40%)"}]}/><Sel label="보유기간 (1주택자)" value={hold} onChange={sHold} options={[{value:"0",label:"5년 미만"},{value:"5",label:"5~10년 (20%)"},{value:"10",label:"10~15년 (40%)"},{value:"15",label:"15년 이상 (50%)"}]}/></div>}
    {n===1&&<div style={{padding:"10px 14px",background:P.lt,borderRadius:8,fontSize:11,color:"#6b778c",lineHeight:1.5,marginTop:8}}>※ 고령자+장기보유 합산 최대 80% 세액공제 (1주택자만)</div>}
  </div>{pp>0?<RP title="종합부동산세" total={finalCt+fm} sub={"공제 "+(n===1?"12억":"9억")+" / 가액비율 60%"} items={[{l:"공시가격 합계",v:fW(pp)},{l:"과세표준",v:fW(tb)},{l:"종부세 (공제전)",v:fW(ct)}].concat(combinedCredit>0?[{l:"고령자공제 ("+Math.round(ageCredit*100)+"%)",v:"-"+fW(Math.round(ct*ageCredit))},{l:"장기보유공제 ("+Math.round(holdCredit*100)+"%)",v:"-"+fW(Math.round(ct*holdCredit))},{l:"합산 공제율 (최대 80%)",v:Math.round(combinedCredit*100)+"%"},{l:"세액공제 합계",v:"-"+fW(creditAmount)}]:[]).concat([{l:"종부세 (공제후)",v:fW(finalCt)},{l:"농어촌특별세 (20%)",v:fW(fm)}])}/>:<Empty icon="🏘️"/>}</div>);}

function CalcProp(){const[pt,sPt]=useState("house");const[p,sP]=useState("");const pp=tW(p),fr=pt==="house"?.6:.7,tb=pp*fr;let tx=0;if(pt==="house")tx=pTx(tb,[[6e7,.001],[1.5e8,.0015],[3e8,.0025],[Infinity,.004]]);else if(pt==="land")tx=pTx(tb,[[5e7,.002],[1e8,.003],[Infinity,.005]]);else tx=tb*.0025;const ci=pt==="house"?Math.round(tb*.0014):0,ed=tx*.2;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏡 재산세</h3><Sel label="부동산 유형" value={pt} onChange={sPt} options={[{value:"house",label:"주택"},{value:"land",label:"토지"},{value:"com",label:"건축물 (상가 등)"}]}/><Inp label="공시가격" value={p} onChange={sP} suffix="만원" placeholder="예: 50000"/></div>{pp>0?<RP title="재산세" total={tx+ci+ed} items={[{l:"과세표준 (공시가×"+(fr*100)+"%)",v:fW(tb)},{l:"재산세",v:fW(tx)},{l:"도시지역분 (14%)",v:fW(ci)},{l:"지방교육세 (20%)",v:fW(ed)}]}/>:<Empty icon="🏡"/>}</div>);}

function CalcGift(){const[rl,sRl]=useState("adult");const[p,sP]=useState("");const[isMarriage,sM]=useState("no");const[priorGift,sPG]=useState("");const g=tW(p),priorW=tW(priorGift),ds={spouse:6e8,adult:5e7,minor:2e7,other:1e7};let d=ds[rl];if(isMarriage==="yes")d+=1e8;const totalGift=g+priorW;const tb=Math.max(0,totalGift-d);const priorTax=priorW>0?pTx(Math.max(0,priorW-d),GB):0;const fullTax=pTx(tb,GB);const thisTax=Math.max(0,fullTax-priorTax);return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🎁 증여세</h3><Sel label="수증자와의 관계" value={rl} onChange={sRl} options={[{value:"spouse",label:"배우자 (공제 6억)"},{value:"adult",label:"성년 자녀 (공제 5천만)"},{value:"minor",label:"미성년 자녀 (공제 2천만)"},{value:"other",label:"기타 친족 (공제 1천만)"}]}/><Tog label="혼인·출산 증여 해당" value={isMarriage} onChange={sM} options={[{value:"no",label:"아니오"},{value:"yes",label:"예 (+1억 추가공제)"}]}/><Inp label="증여 재산가액" value={p} onChange={sP} suffix="만원" placeholder="예: 100000"/><Inp label="10년 내 기증여 금액" value={priorGift} onChange={sPG} suffix="만원" placeholder="없으면 0" note="동일인으로부터 10년 이내 증여받은 금액 합산"/></div>{g>0?<RP title="증여세" total={Math.round(thisTax*.97)} sub={"공제 "+fW(d)+" 적용"} items={[{l:"이번 증여액",v:fW(g)}].concat(priorW>0?[{l:"10년 내 기증여 합산",v:fW(priorW)}]:[]).concat([{l:"합산 과세표준",v:fW(tb)},{l:"합산 산출세액",v:fW(fullTax)}]).concat(priorW>0?[{l:"기납부세액 차감",v:"-"+fW(priorTax)}]:[]).concat([{l:"신고세액공제 (3%)",v:"-"+fW(thisTax*.03)},{l:"이번 납부 증여세",v:fW(Math.round(thisTax*.97))}])}/>:<Empty icon="🎁"/>}</div>);}

function CalcInherit(){const[ta,sTa]=useState("");const[db,sDb]=useState("");const[fn,sFn]=useState("500");const[hasSpouse,sHS]=useState("yes");const t=tW(ta),d=tW(db),f=Math.min(tW(fn),15000000),net=t-d-f,ded=hasSpouse==="yes"?10e8:5e8,tb=Math.max(0,net-ded),tx=pTx(tb,GB);return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>📜 상속세</h3><Inp label="총 상속재산가액" value={ta} onChange={sTa} suffix="만원" placeholder="예: 200000"/><Inp label="채무 (대출 등)" value={db} onChange={sDb} suffix="만원" placeholder="예: 10000"/><Inp label="장례비용" value={fn} onChange={sFn} suffix="만원" note="최대 1,500만원 공제"/><Tog label="배우자 유무" value={hasSpouse} onChange={sHS} options={[{value:"yes",label:"있음 (공제 10억)"},{value:"no",label:"없음 (공제 5억)"}]}/></div>{t>0?<RP title="상속세" total={Math.round(tx*.97)} sub={"상속공제 "+fW(ded)} items={[{l:"순상속재산",v:fW(net)},{l:"상속공제"+(hasSpouse==="yes"?" (일괄+배우자)":" (일괄)"),v:fW(ded)},{l:"과세표준",v:fW(tb)},{l:"산출세액",v:fW(tx)},{l:"예상 납부 (신고공제 후)",v:fW(tx*.97)}]}/>:<Empty icon="📜"/>}</div>);}

function CalcMort(){const[pr,sPr]=useState("");const[rt,sRt]=useState("");const[yr,sYr]=useState("30");const[mt,sMt]=useState("equal");const PP=tW(pr),r=pN(rt)/100/12,n=parseInt(yr)*12;let mp=0,tp=0,ti=0;if(PP>0&&r>0&&n>0){if(mt==="equal"){mp=PP*r*Math.pow(1+r,n)/(Math.pow(1+r,n)-1);tp=mp*n;ti=tp-PP;}else if(mt==="principal"){mp=PP/n+PP*r;ti=(PP*r*(n+1))/2;tp=PP+ti;}else{mp=PP*r;ti=mp*n;tp=PP+ti;}}return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>💵 대출이자 계산</h3><Inp label="대출 원금" value={pr} onChange={sPr} suffix="만원" placeholder="예: 30000"/><Inp label="연이자율" value={rt} onChange={sRt} suffix="%" placeholder="예: 3.5"/><Sel label="대출 기간" value={yr} onChange={sYr} options={[5,10,15,20,25,30,35,40].map(y=>({value:String(y),label:y+"년"}))}/><Tog label="상환 방식" value={mt} onChange={sMt} options={[{value:"equal",label:"원리금균등"},{value:"principal",label:"원금균등"},{value:"bullet",label:"만기일시"}]}/></div>{PP>0&&r>0?<RP title="대출상환 분석" total={mp} sub="월 납입금 기준" items={[{l:mt==="principal"?"첫 달 납입금":"월 납입금",v:fW(mp)},{l:"총 이자 비용",v:fW(ti)},{l:"총 상환금액 (원금+이자)",v:fW(tp)},{l:"원금 대비 이자 비율",v:fP(PP>0?ti/PP*100:0)}]}/>:<Empty icon="💵"/>}</div>);}

function CalcDSR(){const[inc,sInc]=useState("");const[nl,sNl]=useState("");const[nr,sNr]=useState("");const[ny,sNy]=useState("30");const[ep,sEp]=useState("");const[loanType,sLT]=useState("fixed");const[age,sAge]=useState("30");const ai=tW(inc),nlW=tW(nl),epW=tW(ep);const stressRate=loanType==="fixed"?0:loanType==="mixed"?0.0075:0.015;const adjRate=pN(nr)/100+stressRate;const nrV=adjRate/12;const ageVal=parseInt(age);let maxTerm=40;if(ageVal>=50)maxTerm=20;else if(ageVal>=40)maxTerm=30;else if(ageVal>=30)maxTerm=35;const adjYear=Math.min(parseInt(ny),maxTerm);const nn=adjYear*12;let nm=0;if(nlW>0&&nrV>0&&nn>0)nm=nlW*nrV*Math.pow(1+nrV,nn)/(Math.pow(1+nrV,nn)-1);const tot=nm*12+epW*12,dsr=ai>0?tot/ai*100:0;let st="양호",sc="#00875A";if(dsr>40){st="한도 초과";sc="#DE350B";}else if(dsr>30){st="주의";sc="#FF8B00";}return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>💳 DSR 계산</h3><Inp label="연 소득" value={inc} onChange={sInc} suffix="만원" placeholder="예: 5000"/><Inp label="신규 대출금액" value={nl} onChange={sNl} suffix="만원" placeholder="예: 30000"/><Inp label="신규 대출 금리" value={nr} onChange={sNr} suffix="%" placeholder="예: 3.5"/><Tog label="대출 유형" value={loanType} onChange={sLT} options={[{value:"fixed",label:"고정금리"},{value:"mixed",label:"혼합형 (5년 고정)"},{value:"variable",label:"변동금리"}]}/><Sel label="대출 기간" value={ny} onChange={sNy} options={[5,10,15,20,25,30,35,40].map(y=>({value:String(y),label:y+"년"}))}/><Sel label="차주 연령대" value={age} onChange={sAge} options={[{value:"20",label:"20대"},{value:"30",label:"30대"},{value:"40",label:"40대"},{value:"50",label:"50대"},{value:"60",label:"60대"}]}/><Inp label="기존 대출 월 상환액 합계" value={ep} onChange={sEp} suffix="만원" placeholder="없으면 0"/></div>{ai>0&&nlW>0?<div style={{background:"linear-gradient(135deg,#0747A6 0%,#0065FF 100%)",borderRadius:16,padding:"28px 24px",color:"#fff",textAlign:"center"}}><div style={{fontSize:11,letterSpacing:1.5,opacity:.8,marginBottom:16}}>DSR 진단 결과 (스트레스 DSR 반영)</div><div style={{fontSize:52,fontWeight:800,color:sc==="#00875A"?"#57D9A3":sc==="#FF8B00"?"#FFC400":"#FF5630"}}>{fP(dsr)}</div><div style={{fontSize:16,fontWeight:600,marginTop:4,color:sc==="#00875A"?"#57D9A3":sc==="#FF8B00"?"#FFC400":"#FF5630"}}>{st}</div><div style={{fontSize:12,opacity:.7,marginTop:12}}>은행권 40% / 비은행권 50% 기준</div><div style={{borderTop:"1px solid rgba(255,255,255,.2)",marginTop:16,paddingTop:12,textAlign:"left",fontSize:13}}><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>신규 월 상환액</span><span style={{fontWeight:600}}>{fW(nm)}</span></div><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>연간 총 원리금</span><span style={{fontWeight:600}}>{fW(tot)}</span></div><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>스트레스 가산</span><span style={{fontWeight:600}}>{stressRate>0?"+"+fP(stressRate*100)+"p":"없음 (고정)"}</span></div><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>연령별 최대 만기</span><span style={{fontWeight:600}}>{maxTerm}년{parseInt(ny)>maxTerm?" ⚠️":"" }</span></div></div></div>:<Empty icon="💳" msg="소득과 대출 정보를 입력하세요."/>}</div>);}

function CalcComm(){const[ty,sTy]=useState("res");const[tx,sTx]=useState("sale");const[p,sP]=useState("90000");const[dep,sDep]=useState("5000");const[mon,sMon]=useState("50");
  let pW;if(tx==="rent"){const depW=tW(dep),monW=tW(mon);pW=Math.max(depW,depW+monW*100);}else{pW=tW(p);}
  let r=0,mf=Infinity;if(ty==="res"){if(tx==="sale"){if(pW<5e7){r=.006;mf=250000;}else if(pW<2e8){r=.005;mf=800000;}else if(pW<9e8)r=.004;else if(pW<12e8)r=.005;else if(pW<15e8)r=.006;else r=.007;}else{if(pW<5e7){r=.005;mf=200000;}else if(pW<1e8){r=.004;mf=300000;}else if(pW<6e8)r=.003;else if(pW<12e8)r=.004;else if(pW<15e8)r=.005;else r=.006;}}else r=.009;
  const cm=Math.min(pW*r,mf),vt=cm*.1;
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏠 공인중개사 중개보수</h3><Tog label="부동산 유형" value={ty} onChange={sTy} options={[{value:"res",label:"주택"},{value:"com",label:"상가·토지·오피스텔"}]}/><Tog label="거래 유형" value={tx} onChange={sTx} options={[{value:"sale",label:"매매"},{value:"lease",label:"전세"},{value:"rent",label:"월세"}]}/>{tx==="rent"?(<><Inp label="보증금" value={dep} onChange={sDep} suffix="만원" placeholder="예: 5000"/><Inp label="월세" value={mon} onChange={sMon} suffix="만원" placeholder="예: 50"/><div style={{padding:"10px 14px",background:P.lt,borderRadius:8,fontSize:12,color:"#6b778c",lineHeight:1.6,marginBottom:16}}>거래금액 = 보증금 + (월세 × 100) = {fW(pW)}{ty!=="res"&&" (상가 0.9% 이내 협의)"}</div></>):(<Slider label="거래금액" value={p} onChange={sP} min={1000} max={500000} step={500}/>)}</div><RP title="중개보수 (수수료)" total={cm+vt} sub={"상한요율 "+fP(r*100)+" 적용"} items={[{l:"거래금액 기준",v:fW(pW)},{l:"중개보수 (VAT 별도)",v:fW(cm)},{l:"부가가치세 (10%)",v:fW(vt)},{l:"합계 (중개보수+VAT)",v:fW(cm+vt)}]}/></div>);}

function CalcConvert(){const[type,sType]=useState("m2j");const[deposit,sDep]=useState("");const[monthly,sMon]=useState("");const[rate,sRate]=useState("5");const dep=tW(deposit),mon=tW(monthly),rt=pN(rate)/100;let result=0;if(type==="m2j"){result=rt>0?mon*12/rt+dep:0;}else{result=dep>0&&rt>0?(dep*rt)/12:0;}return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🔄 전월세 전환 계산</h3><Tog label="전환 방향" value={type} onChange={sType} options={[{value:"m2j",label:"월세 → 전세"},{value:"j2m",label:"전세 → 월세"}]}/>{type==="m2j"?<><Inp label="보증금" value={deposit} onChange={sDep} suffix="만원" placeholder="예: 5000"/><Inp label="월세" value={monthly} onChange={sMon} suffix="만원" placeholder="예: 80"/></>:<Inp label="전세보증금" value={deposit} onChange={sDep} suffix="만원" placeholder="예: 30000"/>}<Inp label="전환율 (연 %)" value={rate} onChange={sRate} suffix="%" note="2025 법정 전환율 상한: 기준금리+2%"/></div>{(dep>0||mon>0)?<RP title={type==="m2j"?"전세 환산금액":"월세 환산금액"} total={result} sub={"전환율 "+rate+"% 적용"} items={type==="m2j"?[{l:"기존 보증금",v:fW(dep)},{l:"월세 환산 보증금",v:fW(mon*12/(rt||0.01))},{l:"전세 환산 합계",v:fW(result)}]:[{l:"전세보증금",v:fW(dep)},{l:"환산 월세",v:fW(result)},{l:"연 환산 임대료",v:fW(result*12)}]}/>:<Empty icon="🔄"/>}</div>);}

function CalcTotalCost(){const[p,sP]=useState("90000");const[h,sH]=useState("1");const[a,sA]=useState("non");const pW=tW(p);const n=parseInt(h),isR=a!=="non";let acqR;if(n===1||(n===2&&!isR)){acqR=pW<=6e8?.01:pW<=9e8?.02:.03;}else if(n===2&&isR){acqR=.08;}else{acqR=isR?.12:.08;}const ac=pW*acqR,ed=ac*.1,fm=acqR>=.08?pW*.002:pW*.002,tAcq=ac+ed+fm;const rT=pW*.02,rE=rT*.2;let st=pW>1e9?350000:pW>5e8?150000:70000;const tReg=rT+rE+st+15000;let bf=pW<=1e8?160000:pW<=3e8?220000:pW<=5e8?310000:pW<=1e9?420000:600000;const tLeg=bf*1.1+80000;let cr=pW<2e8?.005:pW<9e8?.004:.005;const tComm=pW*cr*1.1;const grand=tAcq+tReg+tLeg+tComm;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>⚡ 매수 총비용 시뮬레이터</h3><Slider label="매수 가격" value={p} onChange={sP} min={1000} max={500000} step={500}/><Radio label="주택 수 (취득 후)" value={h} onChange={sH} options={[{value:"1",label:"1주택"},{value:"2",label:"2주택"},{value:"3",label:"3주택 이상"}]}/><Tog label="지역 구분" value={a} onChange={sA} options={[{value:"non",label:"비규제"},{value:"adj",label:"조정대상"},{value:"spec",label:"투기과열"}]}/></div><RP title="매수 총비용" total={grand} sub={"매수가의 "+(pW>0?(grand/pW*100).toFixed(2):0)+"%"} items={[{l:"취득세+교육세+농특세",v:fW(tAcq)},{l:"등기비용 (등록세+인지세)",v:fW(tReg)},{l:"법무사 수수료",v:fW(tLeg)},{l:"중개보수+VAT",v:fW(tComm)},{l:"실제 필요 총 자금",v:fW(pW+grand)}]}/></div>);}

function CalcCompare(){const[p,sP]=useState("100000");const[rl,sRl]=useState("adult");const pW=tW(p);const saleT=pW*(pW<=6e8?.01:pW<=9e8?.02:.03)*1.1+pW*.002;const gDed={spouse:6e8,adult:5e7,minor:2e7}[rl]||5e7;const giftT=pTx(Math.max(0,pW-gDed),GB)*.97+pW*.035*1.1;const inhT=pTx(Math.max(0,pW-10e8),GB)*.97+pW*.028;const items=[{l:"매매 (취득세 부담)",v:saleT,c:"#0065FF"},{l:"증여 (증여세+취득세)",v:giftT,c:"#6554C0"},{l:"상속 (상속세+등록세)",v:inhT,c:"#00B8D9"}];const mx=Math.max(...items.map(i=>i.v),1);const best=[...items].sort((a,b)=>a.v-b.v)[0];return(<div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>⚡ 매매 vs 증여 vs 상속 세금 비교</h3><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:24}}><Inp label="부동산 시가" value={p} onChange={sP} suffix="만원" placeholder="예: 100000"/><Sel label="이전 대상 (가족 관계)" value={rl} onChange={sRl} options={[{value:"spouse",label:"배우자"},{value:"adult",label:"성년 자녀"},{value:"minor",label:"미성년 자녀"}]}/></div>{pW>0&&<div style={{background:P.card,borderRadius:16,padding:24,border:`1px solid ${P.bd}`}}>{items.map(it=>(<div key={it.l} style={{marginBottom:16}}><div style={{display:"flex",justifyContent:"space-between",marginBottom:6}}><span style={{fontSize:14,fontWeight:600,color:it.c}}>{it.l}</span><span style={{fontSize:15,fontWeight:700}}>{fW(it.v)}</span></div><div style={{background:P.lt,borderRadius:6,height:28,overflow:"hidden"}}><div style={{height:"100%",width:Math.max(it.v/mx*100,3)+"%",background:it.c,borderRadius:6}}/></div></div>))}<div style={{marginTop:16,padding:"12px 16px",background:"#fffff0",border:"1px solid #fefcbf",borderRadius:10,fontSize:13,color:"#744210"}}>{"💡 세금 기준 가장 유리한 방법: "+best.l+" ("+fW(best.v)+")"}<br/>※ 양도세·종부세·향후 세부담까지 종합적으로 세무사 상담 권장</div></div>}</div>);}

function CalcInvest(){const[bp,sBp]=useState("");const[sp,sSp]=useState("");const[hy,sHy]=useState("5");const[ln,sLn]=useState("");const[lr,sLr]=useState("");const[rn,sRn]=useState("");const buyP=tW(bp),sellP=tW(sp),holdY=parseInt(hy),loanW=tW(ln),loanR=pN(lr)/100,rentW=tW(rn);const buyCost=buyP*.015;const totalPT=pTx(buyP*.7*.6,[[6e7,.001],[1.5e8,.0015],[3e8,.0025],[Infinity,.004]])*1.34*holdY;const totalInt=loanW*loanR*holdY;const totalRent=rentW*12*holdY;const sellComm=sellP*.005*1.1;const gain=sellP-buyP;const ltD2=holdY>=3?Math.min(Math.min(holdY,15)*.04+Math.min(holdY,10)*.04,.80):0;const trTax=gain>0?pTx(Math.max(0,gain*(1-ltD2)-2500000),IB)*1.1:0;const totalCost=buyCost+totalPT+totalInt+sellComm+trTax;const totalInc=totalRent+gain;const netProfit=totalInc-totalCost;const invested=buyP-loanW+buyCost;const roi=invested>0?netProfit/invested*100:0;return(<div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>⚡ 투자수익 종합분석 (매수→보유→매도)</h3><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:12,marginBottom:20}}><Inp label="매수가" value={bp} onChange={sBp} suffix="만원" placeholder="예: 70000"/><Inp label="예상 매도가" value={sp} onChange={sSp} suffix="만원" placeholder="예: 100000"/><Sel label="보유 기간" value={hy} onChange={sHy} options={Array.from({length:20},(_,i)=>({value:String(i+1),label:(i+1)+"년"}))}/><Inp label="대출금액" value={ln} onChange={sLn} suffix="만원"/><Inp label="대출 금리" value={lr} onChange={sLr} suffix="%"/><Inp label="월세 수입 (없으면 0)" value={rn} onChange={sRn} suffix="만원"/></div>{buyP>0&&sellP>0&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}><div style={{background:"linear-gradient(135deg,#0747A6,#0065FF)",borderRadius:16,padding:24,color:"#fff"}}><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16,marginBottom:16}}><div><div style={{fontSize:11,opacity:.7}}>총 수익</div><div style={{fontSize:22,fontWeight:800,color:"#57D9A3"}}>{fW(totalInc)}</div></div><div><div style={{fontSize:11,opacity:.7}}>총 비용·세금</div><div style={{fontSize:22,fontWeight:800,color:"#FF5630"}}>{fW(totalCost)}</div></div></div><div style={{borderTop:"1px solid rgba(255,255,255,.2)",paddingTop:16,textAlign:"center"}}><div style={{fontSize:11,opacity:.7}}>순수익</div><div style={{fontSize:32,fontWeight:800,color:netProfit>=0?"#57D9A3":"#FF5630"}}>{fW(netProfit)}</div><div style={{fontSize:14,marginTop:8,opacity:.9}}>투자수익률: <span style={{fontWeight:800,color:"#FFC400"}}>{fP(roi)}</span></div></div></div><div style={{background:P.card,borderRadius:16,padding:20,border:`1px solid ${P.bd}`}}><div style={{fontSize:13,fontWeight:600,color:P.mt,marginBottom:12}}>비용 상세 내역</div>{[["매수 부대비용",buyCost],["보유세 ("+holdY+"년)",totalPT],["대출이자 ("+holdY+"년)",totalInt],["매도 중개보수",sellComm],["양도소득세",trTax],["임대수입 ("+holdY+"년)",totalRent]].map(([l,v],i)=>(<div key={i} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:`1px solid ${P.lt}`,fontSize:13}}><span style={{color:P.mt}}>{l}</span><span style={{fontWeight:600}}>{fW(v)}</span></div>))}</div></div>}</div>);}

function Placeholder({l}){return (<div style={{padding:40,textAlign:"center",color:P.mt}}><div style={{fontSize:48,marginBottom:12}}>🔧</div><div style={{fontSize:16,fontWeight:600}}>{l}</div><div style={{fontSize:13,marginTop:8}}>해당 기능을 준비 중입니다.</div></div>);}

/* DTI */
function CalcDTI(){const[inc,sInc]=useState("");const[la,sLa]=useState("");const[lr,sLr]=useState("");const[ly,sLy]=useState("30");const[ei,sEi]=useState("");const ai=tW(inc),laW=tW(la),lrV=pN(lr)/100/12,lN=parseInt(ly)*12,eiW=tW(ei);let na=0;if(laW>0&&lrV>0&&lN>0)na=laW*lrV*Math.pow(1+lrV,lN)/(Math.pow(1+lrV,lN)-1)*12;const tot=na+eiW*12,dti=ai>0?tot/ai*100:0;let st="양호",sc="#00875A";if(dti>60){st="한도 초과";sc="#DE350B";}else if(dti>50){st="주의";sc="#FF8B00";}return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>📉 DTI 계산</h3><Inp label="연 소득" value={inc} onChange={sInc} suffix="만원" placeholder="예: 5000"/><Inp label="신규 대출금액" value={la} onChange={sLa} suffix="만원" placeholder="예: 30000"/><Inp label="대출 금리" value={lr} onChange={sLr} suffix="%" placeholder="예: 3.5"/><Sel label="대출 기간" value={ly} onChange={sLy} options={[5,10,15,20,25,30,35,40].map(y=>({value:String(y),label:y+"년"}))}/><Inp label="기존 대출 월이자 합계" value={ei} onChange={sEi} suffix="만원" placeholder="없으면 0" note="DTI는 기존 대출의 이자만 포함 (원금 미포함)"/></div>{ai>0&&laW>0?<div style={{background:"linear-gradient(135deg,#0747A6 0%,#0065FF 100%)",borderRadius:16,padding:"28px 24px",color:"#fff",textAlign:"center"}}><div style={{fontSize:11,letterSpacing:1.5,opacity:.8,marginBottom:16}}>DTI 진단 결과</div><div style={{fontSize:52,fontWeight:800,color:sc==="#00875A"?"#57D9A3":sc==="#FF8B00"?"#FFC400":"#FF5630"}}>{fP(dti)}</div><div style={{fontSize:16,fontWeight:600,marginTop:4,color:sc==="#00875A"?"#57D9A3":sc==="#FF8B00"?"#FFC400":"#FF5630"}}>{st}</div><div style={{fontSize:12,opacity:.7,marginTop:12}}>규제 기준: 60%</div><div style={{borderTop:"1px solid rgba(255,255,255,.2)",marginTop:16,paddingTop:12,textAlign:"left",fontSize:13}}><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>신규 연간 원리금</span><span style={{fontWeight:600}}>{fW(na)}</span></div><div style={{display:"flex",justifyContent:"space-between",padding:"6px 0",opacity:.85}}><span>기존 연간 이자</span><span style={{fontWeight:600}}>{fW(eiW*12)}</span></div></div></div>:<Empty icon="📉" msg="소득과 대출 정보를 입력하세요."/>}</div>);}

/* LTV·대출한도 */
function CalcLTV(){const[pv,sPv]=useState("");const[a,sA]=useState("non");const[h,sH]=useState("1");const[ex,sEx]=useState("");const[first,sFirst]=useState("no");const pvW=tW(pv),exW=tW(ex),n=parseInt(h);let ltv=0.70;if(first==="yes"){ltv=0.80;}else if(a==="spec"){ltv=n===1?0.40:0;}else if(a==="adj"){ltv=n===1?0.50:0.30;}else{ltv=n===1?0.70:0.60;}if(n>=3&&a!=="non")ltv=0;if(a==="spec"&&pvW>15e8)ltv=0;const ml=Math.max(0,pvW*ltv-exW);return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🔑 LTV·대출한도</h3><Inp label="주택 가격 (시세)" value={pv} onChange={sPv} suffix="만원" placeholder="예: 90000"/><Tog label="규제지역" value={a} onChange={sA} options={[{value:"non",label:"비규제"},{value:"adj",label:"조정대상"},{value:"spec",label:"투기과열"}]}/><Sel label="주택 수" value={h} onChange={sH} options={[{value:"1",label:"1주택 (무주택 포함)"},{value:"2",label:"2주택"},{value:"3",label:"3주택 이상"}]}/><Tog label="생애최초 구입자" value={first} onChange={sFirst} options={[{value:"no",label:"아니오"},{value:"yes",label:"예 (LTV 80%)"}]}/><Inp label="기존 담보대출 잔액" value={ex} onChange={sEx} suffix="만원" placeholder="없으면 0"/></div>{pvW>0?<RP title={ltv===0?"대출 제한":"LTV·대출한도 분석"} total={ml} sub={ltv===0?(a==="spec"&&pvW>15e8?"투기과열지구 15억 초과 주담대 금지":"규제지역 다주택자 주택담보대출 제한"):"LTV "+fP(ltv*100)+" 적용"} items={[{l:"주택 가격",v:fW(pvW)},{l:"적용 LTV 한도",v:ltv===0?"대출 불가":fP(ltv*100)},{l:"담보인정 가치",v:fW(pvW*ltv)},{l:"기존 대출 차감",v:exW>0?"-"+fW(exW):"없음"},{l:"최대 대출 가능액",v:fW(ml)}]}/>:<Empty icon="🔑"/>}</div>);}

/* 등기비용 */
function CalcReg(){const[tx,sTx]=useState("sale");const[p,sP]=useState("");const pW=tW(p);const rr=tx==="sale"?0.02:tx==="inherit"?0.008:0.015;const rt=pW*rr,ed=rt*0.2;let stamp=0;if(pW>30e8)stamp=350000;else if(pW>10e8)stamp=350000;else if(pW>5e8)stamp=150000;else if(pW>1e8)stamp=70000;const bondRate=pW>6e8?0.05:pW>1.6e8?0.04:0.03;const bondCost=Math.round(pW*bondRate*0.05);const court=15000;const total=rt+ed+stamp+bondCost+court;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>📝 등기비용 계산</h3><Sel label="등기 원인" value={tx} onChange={sTx} options={[{value:"sale",label:"매매 (세율 2%)"},{value:"inherit",label:"상속 (세율 0.8%)"},{value:"gift",label:"증여 (세율 1.5%)"}]}/><Inp label="부동산 가액" value={p} onChange={sP} suffix="만원" placeholder="예: 90000"/></div>{pW>0?<RP title="등기비용 합계" total={total} sub={"등록면허세율 "+(rr*100).toFixed(1)+"%"} items={[{l:"등록면허세",v:fW(rt)},{l:"지방교육세 (20%)",v:fW(ed)},{l:"인지세",v:fW(stamp)},{l:"국민주택채권 할인비용 (약)",v:fW(bondCost)},{l:"법원수수료 (증지대)",v:fW(court)}]}/>:<Empty icon="📝"/>}</div>);}

/* 법무사수수료 */
function CalcLegal(){const[tx,sTx]=useState("sale");const[p,sP]=useState("");const pW=tW(p);let bf=0;if(pW<=5e7)bf=110000;else if(pW<=1e8)bf=160000;else if(pW<=3e8)bf=220000;else if(pW<=5e8)bf=310000;else if(pW<=10e8)bf=420000;else if(pW<=20e8)bf=550000;else if(pW<=30e8)bf=660000;else bf=770000;if(tx==="inherit"||tx==="gift")bf=Math.round(bf*1.3);if(tx==="mortgage")bf=Math.round(bf*0.5);const vat=Math.round(bf*0.1);const doc=50000;const travel=30000;const total=bf+vat+doc+travel;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>⚖️ 법무사 수수료</h3><Sel label="업무 유형" value={tx} onChange={sTx} options={[{value:"sale",label:"매매 (소유권이전)"},{value:"inherit",label:"상속 (약 30% 가산)"},{value:"gift",label:"증여 (약 30% 가산)"},{value:"mortgage",label:"근저당설정"}]}/><Inp label="부동산 가액" value={p} onChange={sP} suffix="만원" placeholder="예: 90000" note="대한법무사협회 보수표 기준 (참고용)"/></div>{pW>0?<RP title="법무사 수수료" total={total} sub="실제 비용은 법무사에 따라 다를 수 있음" items={[{l:"기본 보수",v:fW(bf)},{l:"부가가치세 (10%)",v:fW(vat)},{l:"서류작성비",v:fW(doc)},{l:"교통비 등 부대비용",v:fW(travel)}]}/>:<Empty icon="⚖️"/>}</div>);}

/* 임대수익률 */
function CalcYield(){const[pp,sPP]=useState("");const[dp,sDp]=useState("");const[rn,sRn]=useState("");const[ex,sEx]=useState("");const[ln,sLn]=useState("");const[lr,sLr]=useState("");const ppW=tW(pp),dpW=tW(dp),rnW=tW(rn),exW=tW(ex),lnW=tW(ln),lrV=pN(lr)/100;const aR=rnW*12,aI=lnW*lrV,aE=exW*12,ni=aR-aE-aI,inv=ppW-dpW-lnW;const gr=ppW>0?aR/ppW*100:0,nt=inv>0?ni/inv*100:0;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>📈 임대수익률 분석</h3><Inp label="매입가" value={pp} onChange={sPP} suffix="만원" placeholder="예: 50000"/><Inp label="보증금 (전세금)" value={dp} onChange={sDp} suffix="만원" placeholder="예: 10000"/><Inp label="월세" value={rn} onChange={sRn} suffix="만원" placeholder="예: 100"/><Inp label="월 관리비·경비" value={ex} onChange={sEx} suffix="만원" placeholder="예: 20"/><Inp label="대출금액" value={ln} onChange={sLn} suffix="만원" placeholder="예: 20000"/><Inp label="대출 금리" value={lr} onChange={sLr} suffix="%" placeholder="예: 4.0"/></div>{ppW>0&&rnW>0?<RP title="임대수익률" total={ni} sub={"자기자본 "+fW(inv)+" 기준"} items={[{l:"연간 임대수입",v:fW(aR)},{l:"연간 관리비·경비",v:"-"+fW(aE)},{l:"연간 대출이자",v:"-"+fW(aI)},{l:"연간 순수익",v:fW(ni)},{l:"총수익률 (Gross)",v:fP(gr)},{l:"순수익률 (Net)",v:fP(nt)}]}/>:<Empty icon="📈"/>}</div>);}

/* 평수변환 */
function CalcArea(){const[dir,sDir]=useState("s2p");const[v,sV]=useState("");const val=pN(v),py=3.305785,res=dir==="s2p"?val/py:val*py;const sizes=[{p:18,s:59},{p:24,s:79},{p:25,s:84},{p:32,s:106},{p:34,s:112},{p:43,s:142},{p:50,s:165}];return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>📐 평수 변환</h3><Tog label="변환 방향" value={dir} onChange={sDir} options={[{value:"s2p",label:"㎡ → 평"},{value:"p2s",label:"평 → ㎡"}]}/><Inp label={"면적 ("+(dir==="s2p"?"㎡":"평")+")"} value={v} onChange={sV} placeholder="숫자 입력"/>{val>0&&<div style={{padding:"16px 20px",background:P.lt,borderRadius:12,textAlign:"center",marginTop:8}}><div style={{fontSize:13,color:P.mt}}>{val} {dir==="s2p"?"㎡":"평"} =</div><div style={{fontSize:28,fontWeight:800,color:P.pri,marginTop:4}}>{res.toFixed(2)} {dir==="s2p"?"평":"㎡"}</div></div>}</div><div><h4 style={{fontSize:14,fontWeight:700,color:P.tx,margin:"0 0 12px"}}>주요 아파트 평형 참고</h4><div style={{background:P.card,borderRadius:12,border:`1px solid ${P.bd}`,overflow:"hidden"}}>{sizes.map((s,i)=>(<div key={s.p} style={{display:"flex",justifyContent:"space-between",padding:"10px 16px",borderBottom:i<sizes.length-1?`1px solid ${P.lt}`:"none",fontSize:14}}><span style={{fontWeight:700,color:P.pri}}>{s.p}평형</span><span style={{color:P.mt}}>전용 {s.s}㎡</span></div>))}</div><div style={{marginTop:12,padding:"12px 16px",background:P.lt,borderRadius:10,fontSize:12,color:P.mt,lineHeight:1.6}}>※ 1평 = 3.305785㎡ (정확히 400/121)<br/>※ 전용면적 기준이며, 공급면적은 주거공용 포함</div></div></div>);}

/* 공동명의 */
function CalcJoint(){const[p,sP]=useState("");const[r,sR]=useState("50");const pW=tW(p),rv=pN(r)/100;const sB=Math.max(0,(pW-12e8)*0.6);const j1B=Math.max(0,(pW*rv-9e8*rv)*0.6);const j2B=Math.max(0,(pW*(1-rv)-9e8*(1-rv))*0.6);const C2=[[3e8,.005],[6e8,.007],[12e8,.01],[25e8,.013],[50e8,.02],[94e8,.022],[Infinity,.027]];const sT=pTx(sB,C2),jT=pTx(j1B,C2)+pTx(j2B,C2),sv=sT-jT;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>👥 공동명의 비교 분석</h3><Inp label="부동산 공시가격" value={p} onChange={sP} suffix="만원" placeholder="예: 150000"/><div style={{marginBottom:16}}><label style={{display:"block",fontSize:12,fontWeight:600,color:P.mt,marginBottom:6}}>{"지분 비율 — 본인 "+r+"% : 배우자 "+(100-parseInt(r))+"%"}</label><input type="range" min="10" max="90" step="10" value={r} onChange={e=>sR(e.target.value)} style={{width:"100%",accentColor:P.pri}}/><div style={{display:"flex",justifyContent:"space-between",fontSize:11,color:P.mt,marginTop:4}}><span>본인 10%</span><span>본인 90%</span></div></div><div style={{padding:"14px 16px",background:P.lt,borderRadius:10,fontSize:13,color:"#4a5568",lineHeight:1.6}}><b>단독명의:</b> 1주택 공제 12억, 고령자·장기보유 공제 가능<br/><b>공동명의:</b> 각 9억 공제 (합 18억), 고령자·장기보유 공제 불가</div></div>{pW>0?<RP title={sv>0?"공동명의가 유리":"단독명의가 유리"} total={Math.abs(sv)} sub={"절세액 기준 비교"} items={[{l:"단독명의 종부세",v:fW(sT)},{l:"공동명의 종부세 합계",v:fW(jT)},{l:"차이 (절세액)",v:fW(Math.abs(sv))},{l:"본인 지분 "+r+"%",v:fW(pW*rv)},{l:"배우자 지분 "+(100-parseInt(r))+"%",v:fW(pW*(1-rv))}]}/>:<Empty icon="👥"/>}</div>);}

/* 대출가능액 */
function CalcLoanMax(){const[inc,sInc]=useState("");const[dsrLim,sDsrLim]=useState("40");const[rt,sRt]=useState("");const[yr,sYr]=useState("30");const[ep,sEp]=useState("");const ai=tW(inc),lim=pN(dsrLim)/100,r=pN(rt)/100/12,n=parseInt(yr)*12,epW=tW(ep);const maxAnnual=ai*lim;const maxMonthly=(maxAnnual-epW*12)/12;let maxLoan=0;if(r>0&&n>0&&maxMonthly>0){maxLoan=maxMonthly*(Math.pow(1+r,n)-1)/(r*Math.pow(1+r,n));}const actualDsr=ai>0?(maxMonthly*12+epW*12)/ai*100:0;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>💰 대출가능액 역산</h3><Inp label="연 소득" value={inc} onChange={sInc} suffix="만원" placeholder="예: 5000"/><Tog label="DSR 기준" value={dsrLim} onChange={sDsrLim} options={[{value:"40",label:"은행 40%"},{value:"50",label:"비은행 50%"}]}/><Inp label="대출 금리" value={rt} onChange={sRt} suffix="%" placeholder="예: 3.5"/><Sel label="대출 기간" value={yr} onChange={sYr} options={[5,10,15,20,25,30,35,40].map(y=>({value:String(y),label:y+"년"}))}/><Inp label="기존 대출 월 상환액" value={ep} onChange={sEp} suffix="만원" placeholder="없으면 0"/></div>{ai>0&&r>0?<RP title="최대 대출가능액" total={Math.max(0,maxLoan)} sub={"DSR "+dsrLim+"% 기준"} items={[{l:"연 소득",v:fW(ai)},{l:"DSR 한도 내 연 상환 가능액",v:fW(maxAnnual)},{l:"기존 대출 연 상환액",v:fW(epW*12)},{l:"신규 월 상환 가능액",v:fW(Math.max(0,maxMonthly))},{l:"최대 대출가능액",v:fW(Math.max(0,maxLoan))},{l:"적용 DSR",v:fP(actualDsr)}]}/>:<Empty icon="💰"/>}</div>);}

/* 보유세 통합 */
function CalcHoldTax(){const[h,sH]=useState("1");const[p,sP]=useState("");const pW=tW(p);const n=parseInt(h);const ptBase=pW*0.6;const PTB=[[6e7,.001],[1.5e8,.0015],[3e8,.0025],[Infinity,.004]];const ptTax=pTx(ptBase,PTB);const ptCity=Math.round(ptTax*0.14);const ptEdu=Math.round(ptTax*0.2);const ptTotal=ptTax+ptCity+ptEdu;const cDed=n===1?12e8:9e8;const cBase=Math.max(0,(pW-cDed)*0.6);const CTB=[[3e8,.005],[6e8,.007],[12e8,.01],[25e8,.013],[50e8,.02],[94e8,.022],[Infinity,.027]];const cTax=pTx(cBase,CTB);const cFarm=Math.round(cTax*0.2);const cTotal=cTax+cFarm;const grand=ptTotal+cTotal;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏛️ 보유세 통합 계산</h3><Radio label="주택 수" value={h} onChange={sH} options={[{value:"1",label:"1주택"},{value:"2",label:"2주택"},{value:"3",label:"3주택 이상"}]}/><Inp label="주택 공시가격" value={p} onChange={sP} suffix="만원" placeholder="예: 150000"/></div>{pW>0?<RP title="연간 보유세 합계" total={grand} sub={"공시가 "+fW(pW)+" 기준"} items={[{l:"재산세",v:fW(ptTax)},{l:"도시지역분 (14%)",v:fW(ptCity)},{l:"지방교육세 (20%)",v:fW(ptEdu)},{l:"재산세 소계",v:fW(ptTotal)},{l:"종부세 (공제 "+(cDed/1e8)+"억)",v:fW(cTax)},{l:"농특세 (20%)",v:fW(cFarm)},{l:"종부세 소계",v:fW(cTotal)}]}/>:<Empty icon="🏛️"/>}</div>);}

/* 인지세 */
function CalcStamp(){const[p,sP]=useState("");const pW=tW(p);let stamp=0;if(pW>30e8)stamp=500000;else if(pW>10e8)stamp=350000;else if(pW>1e8)stamp=150000;const half=Math.round(stamp/2);return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>📃 인지세 계산</h3><Inp label="거래금액" value={p} onChange={sP} suffix="만원" placeholder="예: 90000"/><div style={{padding:"14px 16px",background:P.lt,borderRadius:10,fontSize:13,color:"#4a5568",lineHeight:1.6,marginTop:8}}>• 1억 이하: 비과세<br/>• 1억~10억: 15만원<br/>• 10억~30억: 35만원<br/>• 30억 초과: 50만원</div></div>{pW>0?<RP title="인지세" total={stamp} sub={stamp===0?"비과세 구간":"매도·매수인 각 50% 부담"} items={[{l:"거래금액",v:fW(pW)},{l:"인지세액",v:fW(stamp)},{l:"매도인 부담",v:fW(half)},{l:"매수인 부담",v:fW(half)}]}/>:<Empty icon="📃"/>}</div>);}

/* 국민주택채권 할인료 */
function CalcBond(){const[p,sP]=useState("");const[area,sArea]=useState("seoul");const[use,sUse]=useState("house");const pW=tW(p);let bondRate=0;if(use==="house"){if(area==="seoul"){bondRate=pW>6e8?0.05:pW>1.6e8?0.04:0.03;}else if(area==="metro"){bondRate=pW>6e8?0.04:pW>1.6e8?0.03:0.02;}else{bondRate=pW>6e8?0.03:pW>1.6e8?0.02:0.01;}}else{bondRate=area==="seoul"?0.05:area==="metro"?0.04:0.03;}const bondAmt=Math.round(pW*bondRate);const discountRate=0.045;const discountCost=Math.round(bondAmt*discountRate);return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>📜 국민주택채권 할인비용</h3><Inp label="매매 가격" value={p} onChange={sP} suffix="만원" placeholder="예: 90000"/><Tog label="지역" value={area} onChange={sArea} options={[{value:"seoul",label:"서울"},{value:"metro",label:"광역시"},{value:"etc",label:"기타 지역"}]}/><Tog label="용도" value={use} onChange={sUse} options={[{value:"house",label:"주택"},{value:"commercial",label:"상가·오피스텔"}]}/></div>{pW>0?<RP title="채권 할인비용" total={discountCost} sub={"매입률 "+fP(bondRate*100)+" · 할인율 "+fP(discountRate*100)} items={[{l:"매매가격",v:fW(pW)},{l:"채권매입률",v:fP(bondRate*100)},{l:"채권매입액",v:fW(bondAmt)},{l:"할인율 (시세)",v:fP(discountRate*100)},{l:"실제 부담 할인비용",v:fW(discountCost)}]}/>:<Empty icon="📜"/>}</div>);}

/* 예적금이자 */
function CalcDeposit(){const[amt,sAmt]=useState("");const[rt,sRt]=useState("");const[mon,sMon]=useState("12");const[ty,sTy]=useState("saving");const[tax,sTax]=useState("normal");const amtW=tW(amt),r=pN(rt)/100,m=parseInt(mon);const taxRate=tax==="normal"?0.154:tax==="preferential"?0.095:0;let interest=0;if(ty==="saving"){interest=amtW*r*m/12;}else{interest=amtW*r*(m+1)/24*m/m;}const taxAmt=Math.round(interest*taxRate);const afterTax=interest-taxAmt;const total=amtW+afterTax;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏦 예적금 이자 계산</h3><Inp label={ty==="saving"?"예금 원금":"월 납입액"} value={amt} onChange={sAmt} suffix="만원" placeholder="예: 1000"/><Inp label="연이율" value={rt} onChange={sRt} suffix="%" placeholder="예: 3.5"/><Sel label="기간" value={mon} onChange={sMon} options={[3,6,12,18,24,36].map(m=>({value:String(m),label:m+"개월"}))}/><Tog label="상품 유형" value={ty} onChange={sTy} options={[{value:"saving",label:"예금 (거치식)"},{value:"installment",label:"적금 (적립식)"}]}/><Tog label="세금 유형" value={tax} onChange={sTax} options={[{value:"normal",label:"일반 (15.4%)"},{value:"preferential",label:"세금우대 (9.5%)"},{value:"exempt",label:"비과세"}]}/></div>{amtW>0&&r>0?<RP title="세후 수령액" total={total} sub={tax==="exempt"?"비과세 적용":"세율 "+fP(taxRate*100)+" 적용"} items={[{l:ty==="saving"?"예금 원금":"총 납입액",v:fW(ty==="saving"?amtW:amtW*m)},{l:"세전 이자",v:fW(interest)},{l:"이자소득세",v:"-"+fW(taxAmt)},{l:"세후 이자",v:fW(afterTax)},{l:"세후 총 수령액",v:fW(total)}]}/>:<Empty icon="🏦"/>}</div>);}

/* 용적률·건폐율 */
function CalcFAR(){const[land,sLand]=useState("");const[build,sBuild]=useState("");const[floor,sFloor]=useState("");const[base,sBase]=useState("");const landV=pN(land),buildV=pN(build),floorV=pN(floor),baseV=pN(base);const bcr=landV>0?buildV/landV*100:0;const far=landV>0?(floorV-baseV)/landV*100:0;const zones=[{z:"제1종 전용주거",b:"50%",f:"100%"},{z:"제2종 전용주거",b:"50%",f:"150%"},{z:"제1종 일반주거",b:"60%",f:"200%"},{z:"제2종 일반주거",b:"60%",f:"250%"},{z:"제3종 일반주거",b:"50%",f:"300%"},{z:"준주거",b:"70%",f:"500%"},{z:"일반상업",b:"80%",f:"1300%"},{z:"준공업",b:"70%",f:"400%"}];return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏗️ 용적률·건폐율 계산</h3><Inp label="대지면적" value={land} onChange={sLand} placeholder="㎡"/><Inp label="건축면적 (1층 바닥)" value={build} onChange={sBuild} placeholder="㎡"/><Inp label="연면적 (전체 층 합계)" value={floor} onChange={sFloor} placeholder="㎡"/><Inp label="지하면적" value={base} onChange={sBase} placeholder="㎡ (없으면 0)"/>{landV>0&&buildV>0&&<div style={{padding:16,background:P.lt,borderRadius:12,textAlign:"center"}}><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:16}}><div><div style={{fontSize:12,color:P.mt}}>건폐율</div><div style={{fontSize:28,fontWeight:800,color:P.pri}}>{bcr.toFixed(1)}%</div></div><div><div style={{fontSize:12,color:P.mt}}>용적률</div><div style={{fontSize:28,fontWeight:800,color:P.pri}}>{far.toFixed(1)}%</div></div></div></div>}</div><div><h4 style={{fontSize:14,fontWeight:700,color:P.tx,margin:"0 0 12px"}}>용도지역별 법정한도</h4><div style={{background:P.card,borderRadius:12,border:`1px solid ${P.bd}`,overflow:"hidden"}}><div style={{display:"flex",padding:"8px 16px",background:P.lt,fontWeight:600,fontSize:12,color:P.pri}}><span style={{flex:1}}>용도지역</span><span style={{width:60,textAlign:"right"}}>건폐율</span><span style={{width:60,textAlign:"right"}}>용적률</span></div>{zones.map((z,i)=>(<div key={i} style={{display:"flex",padding:"8px 16px",borderBottom:i<zones.length-1?`1px solid ${P.lt}`:"none",fontSize:13}}><span style={{flex:1,color:P.tx}}>{z.z}</span><span style={{width:60,textAlign:"right",color:P.mt}}>{z.b}</span><span style={{width:60,textAlign:"right",color:P.mt}}>{z.f}</span></div>))}</div></div></div>);}

/* 임대소득세 */
function CalcRental(){const[h,sH]=useState("2");const[ri,sRi]=useState("");const[er,sEr]=useState("50");const[bd,sBd]=useState("200");const[mode,sMode]=useState("sep");const riW=tW(ri);const erV=pN(er)/100;const bdW=tW(bd)*10000;const n=parseInt(h);const sepBase=Math.max(0,riW*(1-erV)-bdW);const sepTax=Math.round(sepBase*0.14);const compBase=Math.max(0,riW-riW*0.6-2500000);const compTax=pTx(compBase,IB);const better=sepTax<=compTax?"분리과세":"종합과세";const isExempt=n===1&&riW<=0;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏘️ 주택임대소득세</h3><Radio label="주택 수" value={h} onChange={sH} options={[{value:"1",label:"1주택 (기준시가 12억↑만 과세)"},{value:"2",label:"2주택"},{value:"3",label:"3주택 이상"}]}/><Inp label="연간 임대수입" value={ri} onChange={sRi} suffix="만원" placeholder="예: 1500"/><Inp label="필요경비율" value={er} onChange={sEr} suffix="%" note="분리과세 시 50%, 등록임대 60%"/><Inp label="기본공제" value={bd} onChange={sBd} suffix="만원" note="미등록 200만, 등록 400만"/><Tog label="과세 방식" value={mode} onChange={sMode} options={[{value:"sep",label:"분리과세 (14%)"},{value:"comp",label:"종합과세 (6~45%)"}]}/></div>{riW>0?<RP title={mode==="sep"?"분리과세 임대소득세":"종합과세 임대소득세"} total={mode==="sep"?sepTax:compTax} sub={"유리한 방식: "+better} items={[{l:"연간 임대수입",v:fW(riW)},{l:"분리과세액 (14%)",v:fW(sepTax)},{l:"종합과세 참고액",v:fW(compTax)},{l:"유리한 방식",v:better}]}/>:<Empty icon="🏘️"/>}</div>);}

/* 감정평가수수료 */
function CalcAppraisal(){const[p,sP]=useState("");const pW=tW(p);let fee=0;if(pW<=5e7)fee=200000;else if(pW<=2e8)fee=200000+Math.round((pW-5e7)*0.0009);else if(pW<=5e8)fee=155000+Math.round((pW-2e8)*0.0008);else if(pW<=10e8)fee=395000+Math.round((pW-5e8)*0.0006);else if(pW<=50e8)fee=695000+Math.round((pW-10e8)*0.0004);else if(pW<=100e8)fee=2295000+Math.round((pW-50e8)*0.0002);else fee=2295000+Math.round((pW-100e8)*0.0001);const vat=Math.round(fee*0.1);const total=fee+vat;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🔍 감정평가 수수료</h3><Inp label="감정가액" value={p} onChange={sP} suffix="만원" placeholder="예: 90000"/><div style={{padding:"14px 16px",background:P.lt,borderRadius:10,fontSize:12,color:"#4a5568",lineHeight:1.8,marginTop:8}}>• 5천만 이하: 기본 20만원<br/>• 5천만~2억: 20만 + 초과분×0.09%<br/>• 2~5억: 15.5만 + 초과분×0.08%<br/>• 5~10억: 39.5만 + 초과분×0.06%<br/>• 10~50억: 69.5만 + 초과분×0.04%</div></div>{pW>0?<RP title="감정평가 수수료" total={total} sub="부가세 포함" items={[{l:"감정가액",v:fW(pW)},{l:"기본 수수료",v:fW(fee)},{l:"부가가치세 (10%)",v:fW(vat)},{l:"합계",v:fW(total)}]}/>:<Empty icon="🔍"/>}</div>);}

/* 경매비용 */
function CalcAuction(){const[bp,sBp]=useState("");const[ap,sAp]=useState("");const[fail,sFail]=useState("0");const bpW=tW(bp),apW=tW(ap),failN=parseInt(fail);const ratio=failN>0?Math.pow(0.8,failN):1;const minBid=Math.round(apW*ratio);const acqTax=Math.round(bpW*0.04);const regTax=Math.round(bpW*0.02*1.2);const legalFee=bpW<=3e8?220000:bpW<=5e8?310000:bpW<=10e8?420000:600000;const moveFee=3000000;const total=acqTax+regTax+legalFee+moveFee;const invested=bpW+total;const profit=apW>0?apW-invested:0;const roi=invested>0?profit/invested*100:0;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🔨 경매비용 계산</h3><Inp label="낙찰가 (예상)" value={bp} onChange={sBp} suffix="만원" placeholder="예: 50000"/><Inp label="감정가" value={ap} onChange={sAp} suffix="만원" placeholder="예: 70000"/><Sel label="유찰 횟수" value={fail} onChange={sFail} options={[0,1,2,3,4,5].map(n=>({value:String(n),label:n===0?"신건 (유찰 없음)":n+"회 유찰 (최저가 "+(Math.pow(0.8,n)*100).toFixed(0)+"%)"}))}/></div>{bpW>0?<RP title="경매 총비용" total={total} sub={"실투자금 "+fW(invested)} items={[{l:"낙찰가",v:fW(bpW)},{l:"감정가 대비 최저입찰가",v:apW>0?fW(minBid)+" ("+(ratio*100).toFixed(0)+"%)":"—"},{l:"취득세 (4%)",v:fW(acqTax)},{l:"등기비용",v:fW(regTax)},{l:"법무사 수수료",v:fW(legalFee)},{l:"명도비 (예상)",v:fW(moveFee)},{l:"총 부대비용",v:fW(total)},{l:"실투자금 (낙찰+부대)",v:fW(invested)},{l:"예상수익 (감정가 기준)",v:fW(profit)},{l:"예상수익률",v:fP(roi)}]}/>:<Empty icon="🔨"/>}</div>);}

/* 리모델링수익 */
function CalcRemodel(){const[cv,sCv]=useState("");const[cost,sCost]=useState("");const[ev,sEv]=useState("");const cvW=tW(cv),costW=tW(cost),evW=tW(ev);const profit=evW-cvW-costW;const roi=costW>0?profit/costW*100:0;const totalRoi=(cvW+costW)>0?profit/(cvW+costW)*100:0;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏠 리모델링 수익 분석</h3><Inp label="기존 평가액 (현재 시세)" value={cv} onChange={sCv} suffix="만원" placeholder="예: 80000"/><Inp label="리모델링 분담금" value={cost} onChange={sCost} suffix="만원" placeholder="예: 15000"/><Inp label="리모델링 후 예상가" value={ev} onChange={sEv} suffix="만원" placeholder="예: 120000"/></div>{cvW>0&&costW>0&&evW>0?<RP title={profit>=0?"예상 수익":"예상 손실"} total={Math.abs(profit)} sub={"분담금 대비 수익률 "+fP(roi)} items={[{l:"기존 평가액",v:fW(cvW)},{l:"리모델링 분담금",v:fW(costW)},{l:"총 투자액",v:fW(cvW+costW)},{l:"리모델링 후 예상가",v:fW(evW)},{l:"예상 수익",v:fW(profit)},{l:"분담금 대비 수익률",v:fP(roi)},{l:"총투자 대비 수익률",v:fP(totalRoi)}]}/>:<Empty icon="🏠"/>}</div>);}

/* 건물잔존가치 */
function CalcBldValue(){const[np,sNp]=useState("");const[ul,sUl]=useState("40");const[el,sEl]=useState("");const[mt,sMt]=useState("line");const npW=tW(np),ulV=parseInt(ul),elV=parseInt(el||"0");let remaining=0,depreciation=0;if(npW>0&&ulV>0){if(mt==="line"){const ratio=Math.max(0,Math.min(1,1-elV/ulV));remaining=Math.round(npW*ratio);depreciation=npW-remaining;}else{remaining=Math.round(npW*Math.pow(0.9,elV));depreciation=npW-remaining;}}const pct=npW>0?remaining/npW*100:0;return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏚️ 건물 잔존가치</h3><Inp label="신축 가격 (재조달원가)" value={np} onChange={sNp} suffix="만원" placeholder="예: 50000"/><Sel label="내용연수" value={ul} onChange={sUl} options={[{value:"20",label:"20년 (경량철골)"},{value:"30",label:"30년 (조적·블록)"},{value:"40",label:"40년 (철근콘크리트)"},{value:"50",label:"50년 (SRC)"}]}/><Inp label="경과연수" value={el} onChange={sEl} placeholder="예: 15"/><Tog label="감가 방법" value={mt} onChange={sMt} options={[{value:"line",label:"정액법"},{value:"declining",label:"정률법 (10%)"}]}/></div>{npW>0&&elV>0?<RP title="건물 잔존가치" total={remaining} sub={"잔존률 "+fP(pct)} items={[{l:"신축 가격",v:fW(npW)},{l:"내용연수",v:ulV+"년"},{l:"경과연수",v:elV+"년"},{l:"감가방법",v:mt==="line"?"정액법":"정률법"},{l:"감가상각 누계",v:fW(depreciation)},{l:"잔존가치",v:fW(remaining)},{l:"잔존률",v:fP(pct)}]}/>:<Empty icon="🏚️"/>}</div>);}

/* 종합소득세 */
function CalcIncTax(){const[incType,sIT]=useState("salary");const[gross,sGross]=useState("");const[deductions,sDed]=useState("");const[bizType,sBT]=useState("simple");const[bizRate,sBR]=useState("60");
  const[spouse,sSpouse]=useState("0");const[parents,sParents]=useState("0");const[children,sChildren]=useState("0");const[senior,sSenior]=useState("0");const[disabled,sDisabled]=useState("0");
  const grossW=tW(gross),dedW=tW(deductions);const spouseN=Math.min(parseInt(spouse)||0,1),parentsN=parseInt(parents)||0,childrenN=parseInt(children)||0,seniorN=parseInt(senior)||0,disabledN=parseInt(disabled)||0;
  let taxableIncome=0;
  if(incType==="salary"){let wd=0;if(grossW<=5e6)wd=grossW*.7;else if(grossW<=15e6)wd=3500000+(grossW-5e6)*.4;else if(grossW<=45e6)wd=7500000+(grossW-15e6)*.15;else if(grossW<=1e8)wd=12000000+(grossW-45e6)*.05;else wd=14750000+(grossW-1e8)*.02;taxableIncome=grossW-wd;}
  else if(incType==="biz"||incType==="freelance"){if(bizType==="simple")taxableIncome=grossW*(1-pN(bizRate)/100);else taxableIncome=grossW-dedW;}
  else{taxableIncome=Math.max(0,grossW-Math.max(grossW*.6,dedW));}
  const basicDed=(1+spouseN+parentsN+childrenN)*1500000,seniorDed=seniorN*1000000,disabledDed=disabledN*2000000,personalDed=basicDed+seniorDed+disabledDed;
  const stdDed=incType==="salary"?130000:70000;const finalTaxable=Math.max(0,taxableIncome-personalDed);const tax=pTx(finalTaxable,IB);
  let childCredit=0;if(childrenN===1)childCredit=150000;else if(childrenN===2)childCredit=300000;else if(childrenN>=3)childCredit=300000+(childrenN-2)*300000;
  const finalTax=Math.max(0,tax-stdDed-childCredit);const totalTax=finalTax+finalTax*.1;const prepaid=incType==="freelance"?grossW*.033:0;const toPay=totalTax-prepaid;
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>💼 종합소득세</h3>
    <Tog label="소득 유형" value={incType} onChange={sIT} options={[{value:"salary",label:"근로소득"},{value:"biz",label:"사업소득"},{value:"freelance",label:"프리랜서(3.3%)"},{value:"etc",label:"기타소득"}]}/>
    <Inp label={incType==="salary"?"총급여(연봉)":"총수입금액"} value={gross} onChange={sGross} suffix="만원" placeholder={incType==="salary"?"예: 5000":"예: 8000"}/>
    {(incType==="biz"||incType==="freelance")&&<><Tog label="경비 산정 방식" value={bizType} onChange={sBT} options={[{value:"simple",label:"단순경비율 적용"},{value:"actual",label:"실제 경비 입력"}]}/>{bizType==="simple"?<Sel label="단순경비율" value={bizRate} onChange={sBR} options={[{value:"90",label:"90% (소매업)"},{value:"80",label:"80% (음식점)"},{value:"70",label:"70% (제조업)"},{value:"60",label:"60% (서비스업)"},{value:"50",label:"50% (전문직)"},{value:"40",label:"40% (고소득 전문직)"}]}/>:<Inp label="필요경비 합계" value={deductions} onChange={sDed} suffix="만원" placeholder="실제 지출한 경비"/>}</>}
    {incType==="etc"&&<Inp label="필요경비" value={deductions} onChange={sDed} suffix="만원" note="기타소득은 수입의 60%와 실제 경비 중 큰 금액 적용"/>}
    <div style={{background:P.lt,borderRadius:12,padding:16,marginBottom:16}}>
      <div style={{fontSize:14,fontWeight:700,color:P.tx,marginBottom:12}}>👨‍👩‍👧‍👦 인적공제 대상</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        <Inp label="배우자" value={spouse} onChange={sSpouse} suffix="명" placeholder="0 또는 1" note="연소득 100만원 이하"/>
        <Inp label="60세 이상 부모·조부모" value={parents} onChange={sParents} suffix="명" placeholder="예: 2"/>
        <Inp label="20세 이하 자녀" value={children} onChange={sChildren} suffix="명" placeholder="예: 1"/>
        <Inp label="70세 이상 (경로우대)" value={senior} onChange={sSenior} suffix="명" placeholder="0" note="추가 100만원"/>
        <Inp label="장애인" value={disabled} onChange={sDisabled} suffix="명" placeholder="0" note="추가 200만원"/>
      </div>
    </div>
    {incType==="salary"&&<div style={{padding:"12px 16px",background:P.lt,borderRadius:10,fontSize:12,color:"#6b778c",lineHeight:1.6,marginTop:8}}>※ 4대보험료, 신용카드·의료비·교육비 등 특별공제는 반영되지 않은 간이 계산입니다.</div>}
  </div>{grossW>0?<RP title="종합소득세" total={Math.max(0,toPay)} sub={incType==="salary"?"근로소득 기준 간이세액":incType==="freelance"?"기납부 3.3% 차감 후":"사업소득 기준"} items={[{l:incType==="salary"?"총급여":"총수입금액",v:fW(grossW)},{l:incType==="salary"?"근로소득공제":"필요경비",v:fW(grossW-taxableIncome)},{l:"소득금액",v:fW(taxableIncome)},{l:"기본공제 (본인+가족 "+(1+spouseN+parentsN+childrenN)+"명)",v:"-"+fW(basicDed)}].concat(seniorN>0?[{l:"경로우대공제 ("+seniorN+"명)",v:"-"+fW(seniorDed)}]:[]).concat(disabledN>0?[{l:"장애인공제 ("+disabledN+"명)",v:"-"+fW(disabledDed)}]:[]).concat([{l:"인적공제 합계",v:"-"+fW(personalDed)},{l:"과세표준",v:fW(finalTaxable)},{l:"산출세액",v:fW(tax)},{l:"세액공제 (표준+자녀)",v:"-"+fW(stdDed+childCredit)},{l:"소득세",v:fW(finalTax)},{l:"지방소득세 (10%)",v:fW(finalTax*.1)}]).concat(incType==="freelance"?[{l:"기납부세액 (3.3%)",v:"-"+fW(prepaid)},{l:toPay>=0?"추가 납부":"환급 예상",v:fW(Math.abs(toPay))}]:[{l:"합계 (소득세+지방세)",v:fW(totalTax)}])}/>:<Empty icon="💼" msg="소득 금액을 입력하세요"/>}</div>);}

/* 연말정산 */
function CalcYearEnd(){const[salary,sSal]=useState("");const[card,sCard]=useState("");const[medical,sMed]=useState("");const[edu,sEdu]=useState("");const[donate,sDon]=useState("");const[insurance,sIns]=useState("");const[pension,sPen]=useState("");
  const[spouse,sSpouse]=useState("0");const[parents,sParents]=useState("0");const[children,sChildren]=useState("0");const[senior,sSenior]=useState("0");const[disabled,sDisabled]=useState("0");
  const salW=tW(salary),cardW=tW(card),medW=tW(medical),eduW=tW(edu),donW=tW(donate),insW=tW(insurance),penW=tW(pension);
  const spouseN=Math.min(parseInt(spouse)||0,1),parentsN=parseInt(parents)||0,childN=parseInt(children)||0,seniorN=parseInt(senior)||0,disabledN=parseInt(disabled)||0;
  let workDed=0;if(salW<=5e6)workDed=salW*.7;else if(salW<=15e6)workDed=3500000+(salW-5e6)*.4;else if(salW<=45e6)workDed=7500000+(salW-15e6)*.15;else if(salW<=1e8)workDed=12000000+(salW-45e6)*.05;else workDed=14750000+(salW-1e8)*.02;
  const basicDed=(1+spouseN+parentsN+childN)*1500000,seniorDed=seniorN*1000000,disabledDed=disabledN*2000000,personalDed=basicDed+seniorDed+disabledDed;
  const npn=salW*.045,hi=salW*.03545,ei=salW*.009,socialDed=npn+hi+ei;
  const cardThreshold=salW*.25,cardDed=Math.min(Math.max(0,(cardW-cardThreshold)*.15),3000000);
  const penCredit=Math.min(penW,4000000)*(salW<=55e6?.15:.12);const insCredit=Math.min(insW,1000000)*.12;
  const medThreshold=salW*.03,medCredit=Math.min(Math.max(0,(medW-medThreshold)*.15),7000000*.15);
  const eduCredit=Math.min(eduW,childN>0?3000000*childN:eduW)*.15;
  const donCredit=donW<=10000000?donW*.15:10000000*.15+(donW-10000000)*.30;
  let childCredit=0;if(childN===1)childCredit=150000;else if(childN===2)childCredit=300000;else if(childN>=3)childCredit=300000+(childN-2)*300000;
  const taxableIncome=Math.max(0,salW-workDed-personalDed-socialDed-cardDed);const tax=pTx(taxableIncome,IB);
  const totalCredit=penCredit+insCredit+medCredit+eduCredit+donCredit+childCredit+130000;const finalTax=Math.max(0,tax-totalCredit);const localTax=finalTax*.1;
  const prepaid=pTx(Math.max(0,salW-workDed-personalDed-socialDed),IB);const refund=prepaid-(finalTax+localTax);
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🧾 연말정산</h3>
    <Inp label="총급여 (연봉)" value={salary} onChange={sSal} suffix="만원" placeholder="예: 5000"/>
    <div style={{background:P.lt,borderRadius:12,padding:16,marginBottom:16}}>
      <div style={{fontSize:14,fontWeight:700,color:P.tx,marginBottom:12}}>👨‍👩‍👧‍👦 인적공제 대상</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        <Inp label="배우자" value={spouse} onChange={sSpouse} suffix="명" placeholder="0 또는 1" note="연소득 100만원 이하"/>
        <Inp label="60세 이상 부모" value={parents} onChange={sParents} suffix="명" placeholder="예: 2"/>
        <Inp label="20세 이하 자녀" value={children} onChange={sChildren} suffix="명" placeholder="예: 1"/>
        <Inp label="70세 이상 경로우대" value={senior} onChange={sSenior} suffix="명" placeholder="0" note="추가 100만원"/>
        <Inp label="장애인" value={disabled} onChange={sDisabled} suffix="명" placeholder="0" note="추가 200만원"/>
      </div>
    </div>
    <Inp label="신용카드·체크카드·현금영수증" value={card} onChange={sCard} suffix="만원" placeholder="예: 2000"/>
    <Inp label="의료비 지출액" value={medical} onChange={sMed} suffix="만원" placeholder="예: 300"/>
    <Inp label="교육비 (본인+자녀)" value={edu} onChange={sEdu} suffix="만원" placeholder="예: 500"/>
    <Inp label="연금저축 납입액" value={pension} onChange={sPen} suffix="만원" placeholder="최대 400만원" note="IRP 포함 시 최대 700만원"/>
    <Inp label="보장성 보험료" value={insurance} onChange={sIns} suffix="만원" placeholder="최대 100만원"/>
    <Inp label="기부금" value={donate} onChange={sDon} suffix="만원" placeholder="예: 100"/>
  </div>{salW>0?<RP title={refund>=0?"예상 환급액":"추가 납부 예상"} total={Math.abs(refund)} sub={refund>=0?"돌려받는 금액":"더 내야 할 금액"} items={[{l:"총급여",v:fW(salW)},{l:"근로소득공제",v:"-"+fW(workDed)},{l:"기본공제 (본인+가족 "+(1+spouseN+parentsN+childN)+"명)",v:"-"+fW(basicDed)}].concat(seniorN>0?[{l:"경로우대공제 ("+seniorN+"명)",v:"-"+fW(seniorDed)}]:[]).concat(disabledN>0?[{l:"장애인공제 ("+disabledN+"명)",v:"-"+fW(disabledDed)}]:[]).concat([{l:"인적공제 합계",v:"-"+fW(personalDed)},{l:"4대보험료 공제",v:"-"+fW(socialDed)},{l:"신용카드 소득공제",v:"-"+fW(cardDed)},{l:"과세표준",v:fW(taxableIncome)},{l:"산출세액",v:fW(tax)},{l:"세액공제 합계",v:"-"+fW(totalCredit)},{l:"결정세액",v:fW(finalTax)},{l:"지방소득세",v:fW(localTax)},{l:"기납부세액 (추정)",v:fW(prepaid)},{l:refund>=0?"예상 환급":"추가 납부",v:fW(Math.abs(refund))}])}/>:<Empty icon="🧾" msg="총급여를 입력하세요"/>}</div>);}

/* 연봉 실수령액 */
function CalcNetSalary(){const[salary,sSal]=useState("");const[family,sFamily]=useState("1");const[child,sChild]=useState("0");const[nonTax,sNT]=useState("20");
  const salW=tW(salary),nonTaxW=tW(nonTax)*12,familyN=parseInt(family),childN=parseInt(child),taxableSal=Math.max(0,salW-nonTaxW);
  const monthlySal=taxableSal/12;const npn=Math.min(monthlySal,5900000)*.045,hi=monthlySal*.03545,ltc=hi*.1295,ei=monthlySal*.009;const monthlyIns=npn+hi+ltc+ei;const totalIns=monthlyIns*12;
  let workDed=0;if(taxableSal<=5e6)workDed=taxableSal*.7;else if(taxableSal<=15e6)workDed=3500000+(taxableSal-5e6)*.4;else if(taxableSal<=45e6)workDed=7500000+(taxableSal-15e6)*.15;else if(taxableSal<=1e8)workDed=12000000+(taxableSal-45e6)*.05;else workDed=14750000+(taxableSal-1e8)*.02;
  const personalDed=1500000*familyN+1500000*childN;const taxableIncome=Math.max(0,taxableSal-workDed-personalDed-totalIns);const tax=pTx(taxableIncome,IB);const localTax=tax*.1;
  const monthlyGross=salW/12,monthlyTax=(tax+localTax)/12,monthlyNet=monthlyGross-monthlyIns-monthlyTax;
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>💰 연봉 실수령액</h3>
    <Inp label="연봉 (세전)" value={salary} onChange={sSal} suffix="만원" placeholder="예: 5000"/>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}><Sel label="부양가족 (본인 포함)" value={family} onChange={sFamily} options={[1,2,3,4,5,6].map(n=>({value:String(n),label:n+"명"}))}/><Sel label="20세 이하 자녀" value={child} onChange={sChild} options={[0,1,2,3,4].map(n=>({value:String(n),label:n+"명"}))}/></div>
    <div style={{padding:"10px 14px",background:P.lt,borderRadius:8,fontSize:11,color:"#6b778c",lineHeight:1.5,marginBottom:16}}>※ 부양가족: 본인 포함, 60세 이상 부모도 가능 (부모 연소득 100만원 이하)</div>
    <Inp label="월 비과세액 (식대 등)" value={nonTax} onChange={sNT} suffix="만원" note="식대 20만+자가운전보조 20만 등"/>
  </div>{salW>0?<div>
    <div style={{background:"linear-gradient(135deg,#0747A6,#0065FF)",borderRadius:16,padding:"28px 24px",color:"#fff",textAlign:"center",marginBottom:16}}>
      <div style={{fontSize:11,letterSpacing:1.5,opacity:.7,marginBottom:8}}>월 실수령액</div>
      <div style={{fontSize:42,fontWeight:800}}>{fW(Math.round(monthlyNet))}</div>
      <div style={{fontSize:13,opacity:.6,marginTop:8}}>연 실수령액: {fW(Math.round(monthlyNet*12))}</div>
    </div>
    <div style={{background:P.card,borderRadius:16,padding:20,border:"1px solid "+P.bd}}>
      <div style={{fontSize:13,fontWeight:600,color:P.mt,marginBottom:12}}>월급 구성 상세</div>
      {[["월급여 (세전)",monthlyGross,"+","#0747A6"],["국민연금 (4.5%)",npn,"-","#DE350B"],["건강보험 (3.545%)",hi,"-","#DE350B"],["장기요양 (12.95%)",ltc,"-","#DE350B"],["고용보험 (0.9%)",ei,"-","#DE350B"],["소득세 (간이)",tax/12,"-","#FF8B00"],["지방소득세 (10%)",localTax/12,"-","#FF8B00"]].map(([l,v,s,c],i)=>(<div key={i} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid "+P.lt,fontSize:13}}><span style={{color:i===0?P.tx:P.mt}}>{l}</span><span style={{fontWeight:600,color:c}}>{s}{fW(Math.round(v))}</span></div>))}
      <div style={{display:"flex",justifyContent:"space-between",padding:"12px 0 0",fontSize:15,fontWeight:700}}><span style={{color:P.tx}}>월 실수령액</span><span style={{color:"#0747A6"}}>{fW(Math.round(monthlyNet))}</span></div>
    </div>
  </div>:<Empty icon="💰" msg="연봉을 입력하세요"/>}</div>);}

/* 국민연금 수령액 */
function CalcPension(){const[age,sAge]=useState("35");const[salary,sSal]=useState("350");const[paidYears,sPY]=useState("10");const[retireAge,sRA]=useState("65");
  const ageVal=parseInt(age),salW=tW(salary)*10000,paidY=parseInt(paidYears),retireA=parseInt(retireAge),remainYears=Math.max(0,retireA-ageVal),totalYears=paidY+remainYears;
  const baseSal=Math.min(Math.max(salW,370000),5900000),avgA=2830000,B=baseSal,replaceRate=.40;
  let monthlyPension=0;if(totalYears>=10)monthlyPension=Math.round((avgA+B)*replaceRate*(Math.min(totalYears,40)/40));
  const earlyYears=Math.max(0,65-retireA),earlyDiscount=Math.min(earlyYears*.06,.30),earlyPension=Math.round(monthlyPension*(1-earlyDiscount));
  const lateYears=Math.max(0,retireA-65),lateBonus=Math.min(lateYears*.072,.36),latePension=Math.round(monthlyPension*(1+lateBonus));
  const actualPension=retireA<65?earlyPension:retireA>65?latePension:monthlyPension;
  const monthlyPayment=Math.round(baseSal*.045),totalPaid=monthlyPayment*(paidY+remainYears)*12,expectLife=83,receiveYears=Math.max(0,expectLife-retireA),totalReceive=actualPension*12*receiveYears;
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>👴 국민연금 예상수령액</h3>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}><Sel label="현재 나이" value={age} onChange={sAge} options={Array.from({length:45},(_,i)=>({value:String(i+20),label:(i+20)+"세"}))}/><Sel label="수령 시작 나이" value={retireAge} onChange={sRA} options={[{value:"60",label:"60세 (조기 -30%)"},{value:"62",label:"62세 (-18%)"},{value:"65",label:"65세 (정상)"},{value:"67",label:"67세 (+14.4%)"},{value:"70",label:"70세 (+36%)"}]}/></div>
    <Inp label="현재 월 급여 (세전)" value={salary} onChange={sSal} suffix="만원" placeholder="예: 350"/>
    <Sel label="현재까지 납입 기간" value={paidYears} onChange={sPY} options={Array.from({length:36},(_,i)=>({value:String(i),label:i+"년"}))}/>
    <div style={{padding:"12px 16px",background:P.lt,borderRadius:10,fontSize:12,color:"#6b778c",lineHeight:1.7,marginTop:8}}>※ 최소 10년 이상 납입 필요 / 소득대체율 40% / 기준소득 상한 590만원</div>
  </div>{baseSal>0?<div>
    <div style={{background:"linear-gradient(135deg,#0747A6,#0065FF)",borderRadius:16,padding:"28px 24px",color:"#fff",textAlign:"center",marginBottom:16}}>
      <div style={{fontSize:11,letterSpacing:1.5,opacity:.7,marginBottom:8}}>월 예상 수령액</div>
      <div style={{fontSize:42,fontWeight:800}}>{totalYears>=10?fW(actualPension):"가입기간 부족"}</div>
      {totalYears>=10&&<div style={{fontSize:13,opacity:.6,marginTop:4}}>{retireA<65?"조기수령 "+Math.round(earlyDiscount*100)+"% 감액":retireA>65?"연기수령 "+Math.round(lateBonus*100)+"% 가산":"정상 수령"}</div>}
    </div>
    <div style={{background:P.card,borderRadius:16,padding:20,border:"1px solid "+P.bd}}>
      {[["기준소득월액",fW(baseSal)],["월 납입액 (4.5%)",fW(monthlyPayment)],["총 가입기간",totalYears+"년"+(totalYears<10?" ⚠️":"")],["총 납입 예상액",fW(totalPaid)],["기본 연금액 (65세)",fW(monthlyPension)+"/월"]].concat(retireA!==65?[["조정 후 연금액",fW(actualPension)+"/월"]]:[]).concat([["총 수령 예상 ("+expectLife+"세)",fW(totalReceive)],["납입 대비 수령",totalPaid>0?(totalReceive/totalPaid).toFixed(1)+"배":""]]).map(([l,v],i)=>(<div key={i} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid "+P.lt,fontSize:13}}><span style={{color:P.mt}}>{l}</span><span style={{fontWeight:600,color:l.includes("⚠️")?"#DE350B":P.tx}}>{v}</span></div>))}
    </div>
  </div>:<Empty icon="👴" msg="급여 정보를 입력하세요"/>}</div>);}

/* 퇴직금 */
function CalcRetire(){const[monthly,sM]=useState("");const[years,sY]=useState("");const[months,sMo]=useState("0");
  const monthlyW=tW(monthly),y=parseInt(years)||0,m=parseInt(months)||0,totalDays=y*365+m*30;
  const severance=Math.round(monthlyW*totalDays/365);
  const taxBase=Math.max(0,severance-severance*0.4);const retireTax=y>0?pTx(taxBase/y,IB)*y*0.7:0;
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>💼 퇴직금 계산기</h3>
    <Inp label="최근 3개월 평균 월급 (세전)" value={monthly} onChange={sM} suffix="만원" placeholder="예: 400"/>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}><Inp label="근속 년수" value={years} onChange={sY} suffix="년" placeholder="예: 5"/><Sel label="추가 개월수" value={months} onChange={sMo} options={Array.from({length:12},(_,i)=>({value:String(i),label:i+"개월"}))}/></div>
    <div style={{padding:"12px 16px",background:P.lt,borderRadius:10,fontSize:12,color:"#6b778c",lineHeight:1.6,marginTop:8}}>※ 퇴직금 = 1일 평균임금 × 30일 × (근속일수/365) / ※ 1년 이상 근무 시 수령 자격</div>
  </div>{monthlyW>0&&y>=1?<RP title="예상 퇴직금" total={severance} sub={y+"년 "+m+"개월 근속 기준"} items={[{l:"월 평균임금",v:fW(monthlyW)},{l:"근속기간",v:y+"년 "+m+"개월 ("+totalDays+"일)"},{l:"퇴직금 (세전)",v:fW(severance)},{l:"퇴직소득세 (추정)",v:fW(Math.round(retireTax))},{l:"실수령 퇴직금 (추정)",v:fW(severance-Math.round(retireTax))}]}/>:<Empty icon="💼" msg="월급과 근속기간을 입력하세요"/>}</div>);}

/* 실업급여 */
function CalcUnemploy(){const[age,sAge]=useState("30");const[years,sY]=useState("3");const[daily,sD]=useState("");
  const dailyW=tW(daily)/10000*10000;const ageV=parseInt(age),yV=parseInt(years);
  const minWage2026=10030,minDaily=Math.round(minWage2026*8*0.8),maxDaily=66000;
  const calcDaily=dailyW>0?Math.min(Math.max(Math.round(dailyW*0.6),minDaily),maxDaily):0;
  let duration=120;if(ageV<50){if(yV>=10)duration=210;else if(yV>=5)duration=180;else if(yV>=3)duration=150;else if(yV>=1)duration=120;}else{if(yV>=10)duration=270;else if(yV>=5)duration=240;else if(yV>=3)duration=210;else if(yV>=1)duration=180;}
  const totalAmount=calcDaily*duration,monthlyAmount=Math.round(calcDaily*30);
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏢 실업급여 계산기</h3>
    <Inp label="퇴직 전 1일 평균임금" value={daily} onChange={sD} suffix="원" placeholder="예: 150000" note="최근 3개월 급여총액 ÷ 근무일수"/>
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}><Sel label="퇴직 시 나이" value={age} onChange={sAge} options={[{value:"30",label:"50세 미만"},{value:"50",label:"50세 이상"}]}/><Sel label="고용보험 가입기간" value={years} onChange={sY} options={[{value:"1",label:"1~3년 미만"},{value:"3",label:"3~5년"},{value:"5",label:"5~10년"},{value:"10",label:"10년 이상"}]}/></div>
    <div style={{padding:"12px 16px",background:P.lt,borderRadius:10,fontSize:12,color:"#6b778c",lineHeight:1.6,marginTop:8}}>※ 자발적 퇴직은 원칙적 수급 불가 (예외 있음) / ※ 실업급여 = 평균임금 60% (하한: 최저임금 80%)</div>
  </div>{dailyW>0?<RP title="실업급여 예상" total={monthlyAmount} sub={"월 수령액 기준 · 최대 "+duration+"일"} items={[{l:"1일 평균임금",v:fmt(dailyW)+"원"},{l:"1일 실업급여액 (60%)",v:fmt(calcDaily)+"원"},{l:"하한액 (최저임금80%)",v:fmt(minDaily)+"원"},{l:"수급 기간",v:duration+"일 (약 "+(duration/30).toFixed(1)+"개월)"},{l:"월 수령액 (30일)",v:fmt(monthlyAmount)+"원"},{l:"총 수령액",v:fmt(totalAmount)+"원"}]}/>:<Empty icon="🏢" msg="평균임금을 입력하세요"/>}</div>);}

/* 자동차세 */
function CalcCarTax(){const[carType,sCT]=useState("normal");const[cc,sCC]=useState("2000");const[year,sYear]=useState("0");const[isElec,sElec]=useState("no");
  const ccVal=parseInt(cc)||0,yearVal=parseInt(year)||0;let baseTax=0;
  if(isElec==="yes"){baseTax=100000;}else if(carType==="normal"){baseTax=ccVal<=1000?ccVal*80:ccVal<=1600?ccVal*140:ccVal*200;}else{baseTax=ccVal<=1000?ccVal*18:ccVal<=1600?ccVal*18:ccVal*19;}
  let discount=0;if(yearVal>=3)discount=Math.min((yearVal-2)*.05,.50);
  const discountedTax=Math.round(baseTax*(1-discount)),localEdu=Math.round(discountedTax*.3),totalYear=discountedTax+localEdu,halfYear=Math.round(totalYear/2);
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🚗 자동차세</h3>
    <Tog label="전기·수소차 여부" value={isElec} onChange={sElec} options={[{value:"no",label:"내연기관"},{value:"yes",label:"전기차·수소차"}]}/>
    {isElec==="no"&&<><Tog label="차량 용도" value={carType} onChange={sCT} options={[{value:"normal",label:"비영업용 (자가용)"},{value:"biz",label:"영업용"}]}/><Inp label="배기량" value={cc} onChange={sCC} suffix="cc" placeholder="예: 2000" note="차량등록증 확인"/></>}
    <Sel label="차량 연식" value={year} onChange={sYear} options={[{value:"0",label:"신차 (1년 미만)"},{value:"1",label:"1년"},{value:"2",label:"2년"},{value:"3",label:"3년 (5% 할인)"},{value:"5",label:"5년 (15%)"},{value:"7",label:"7년 (25%)"},{value:"10",label:"10년 (40%)"},{value:"12",label:"12년+ (50% 최대)"}]}/>
    <div style={{padding:"12px 16px",background:P.lt,borderRadius:10,fontSize:12,color:"#6b778c",lineHeight:1.6,marginTop:8}}>※ 6월·12월 연 2회 납부 / 1월 연납 시 약 5% 할인</div>
  </div><RP title="자동차세 (연간)" total={totalYear} sub={discount>0?"차령 할인 "+Math.round(discount*100)+"%":"할인 없음 (3년 미만)"} items={[{l:"기본 자동차세",v:fW(baseTax)},{l:"차령 할인",v:discount>0?"-"+fW(baseTax-discountedTax):"해당없음"},{l:"할인 후 자동차세",v:fW(discountedTax)},{l:"지방교육세 (30%)",v:fW(localEdu)},{l:"연간 합계",v:fW(totalYear)},{l:"반기별 납부액",v:fW(halfYear)},{l:"1월 연납 시 (5% 할인)",v:fW(Math.round(totalYear*.95))}]}/></div>);}

/* 4대보험료 */
function CalcInsurance4(){const[type,sType]=useState("worker");const[salary,sSal]=useState("");const[bonus,sBonus]=useState("");
  const salW=tW(salary),bonusW=tW(bonus),annualSal=salW*12+bonusW,monthlySal=annualSal/12;
  const npnCap=5900000,npnBase=Math.min(monthlySal,npnCap),npn=Math.round(npnBase*.045),hi=Math.round(monthlySal*.03545),ltc=Math.round(hi*.1295),ei=Math.round(monthlySal*.009),workerTotal=npn+hi+ltc+ei;
  const empNpn=npn,empHi=hi,empLtc=ltc,empEi=Math.round(monthlySal*.009),empSan=Math.round(monthlySal*.007),empTotal=empNpn+empHi+empLtc+empEi+empSan;
  const selfHi=Math.round(monthlySal*.03545),selfNpn=Math.round(Math.min(monthlySal,npnCap)*.09),selfTotal=selfHi+Math.round(selfHi*.1295)+selfNpn;
  const isWorker=type==="worker",total=isWorker?workerTotal:selfTotal;
  return(<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:32,alignItems:"start"}}><div><h3 style={{fontSize:18,fontWeight:700,color:P.tx,margin:"0 0 20px"}}>🏥 4대보험료</h3>
    <Tog label="가입 유형" value={type} onChange={sType} options={[{value:"worker",label:"직장인"},{value:"self",label:"개인사업자"},{value:"freelance",label:"프리랜서"}]}/>
    <Inp label="월 급여 (세전)" value={salary} onChange={sSal} suffix="만원" placeholder="예: 350"/>
    {isWorker&&<Inp label="연간 상여금" value={bonus} onChange={sBonus} suffix="만원" placeholder="없으면 0"/>}
    <div style={{padding:"12px 16px",background:P.lt,borderRadius:10,fontSize:12,color:"#6b778c",lineHeight:1.6,marginTop:8}}>※ 2025년 기준 / 국민연금 상한 590만원{isWorker?" / 산재보험은 사업주 전액 부담":" / 지역가입자 전액 본인 부담"}</div>
  </div>{monthlySal>0?<div>
    <div style={{background:"linear-gradient(135deg,#0747A6,#0065FF)",borderRadius:16,padding:24,color:"#fff",textAlign:"center",marginBottom:16}}>
      <div style={{fontSize:11,letterSpacing:1.5,opacity:.7,marginBottom:8}}>{isWorker?"근로자 월 부담액":"월 보험료 합계"}</div>
      <div style={{fontSize:36,fontWeight:800}}>{fW(total)}</div>
      <div style={{fontSize:13,opacity:.6,marginTop:4}}>월 급여 대비 {(total/monthlySal*100).toFixed(1)}%</div>
    </div>
    <div style={{background:P.card,borderRadius:16,padding:20,border:"1px solid "+P.bd}}>
      <div style={{fontSize:13,fontWeight:600,color:P.mt,marginBottom:12}}>{isWorker?"근로자 부담":"본인 부담"}</div>
      {(isWorker?[["국민연금 (4.5%)",npn],["건강보험 (3.545%)",hi],["장기요양 (12.95%)",ltc],["고용보험 (0.9%)",ei]]:[["국민연금 (9%)",selfNpn],["건강보험 (3.545%)",selfHi],["장기요양 (12.95%)",Math.round(selfHi*.1295)]]).map(([l,v],i)=>(<div key={i} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid "+P.lt,fontSize:13}}><span style={{color:P.mt}}>{l}</span><span style={{fontWeight:600,color:"#DE350B"}}>-{fW(v)}</span></div>))}
      <div style={{display:"flex",justifyContent:"space-between",padding:"12px 0 0",fontSize:15,fontWeight:700}}><span>합계</span><span style={{color:"#0747A6"}}>{fW(total)}</span></div>
      {isWorker&&<><div style={{fontSize:13,fontWeight:600,color:P.mt,marginTop:20,marginBottom:12}}>사업주 부담</div>{[["국민연금",empNpn],["건강보험",empHi],["장기요양",empLtc],["고용보험",empEi],["산재보험 (평균)",empSan]].map(([l,v],i)=>(<div key={i} style={{display:"flex",justifyContent:"space-between",padding:"6px 0",borderBottom:"1px solid "+P.lt,fontSize:12}}><span style={{color:P.mt}}>{l}</span><span style={{fontWeight:600}}>{fW(v)}</span></div>))}<div style={{display:"flex",justifyContent:"space-between",padding:"10px 0 0",fontSize:14,fontWeight:700}}><span>사업주 합계</span><span>{fW(empTotal)}</span></div></>}
    </div>
  </div>:<Empty icon="🏥" msg="월 급여를 입력하세요"/>}</div>);}

