function EconCalendar({liveData,isMo,setCat,setCalc,setPage}){
  const[calMonth,setCalMonth]=useState(new Date().getMonth()+1);const[calYear,setCalYear]=useState(new Date().getFullYear());const[filter,setFilter]=useState("all");
  const prevM=()=>{if(calMonth<=1){setCalMonth(12);setCalYear(y=>y-1)}else setCalMonth(m=>m-1)};
  const nextM=()=>{if(calMonth>=12){setCalMonth(1);setCalYear(y=>y+1)}else setCalMonth(m=>m+1)};
  const isThis=calMonth===new Date().getMonth()+1&&calYear===new Date().getFullYear();const today=new Date().getDate();
  const events=liveData?.econCalendar?.[String(calMonth)]||[];const filtered=filter==="all"?events:events.filter(e=>e.cat===filter);
  const firstDay=new Date(calYear,calMonth-1,1).getDay();const daysInMonth=new Date(calYear,calMonth,0).getDate();
  const weeks=[];let week=Array(7).fill(null);
  for(let d=1;d<=daysInMonth;d++){const dow=(firstDay+d-1)%7;const dayEv=filtered.filter(e=>e.day===d||(e.end&&d>=e.day&&d<=e.end));week[dow]={day:d,events:dayEv};if(dow===6||d===daysInMonth){weeks.push([...week]);week=Array(7).fill(null);}}
  return(<div style={{maxWidth:1100,margin:"0 auto",padding:"48px 24px"}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20,flexWrap:"wrap",gap:8}}>
      <div><h2 style={{fontSize:isMo?20:24,fontWeight:800,color:"#172B4D",margin:"0 0 4px"}}>생활경제 달력</h2><p style={{fontSize:13,color:"#6b778c",margin:0}}>세금 납부·금통위·FOMC·CPI 주요 일정</p>
        {(()=>{if(!isThis)return null;const today=new Date().getDate();const upcoming=events.filter(e=>e.day>=today&&e.urgent).sort((a,b)=>a.day-b.day)[0];if(!upcoming)return null;const dDay=upcoming.day-today;return(<div style={{display:"inline-flex",alignItems:"center",gap:6,background:dDay<=3?"#FFEBE6":"#FFF8E1",padding:"6px 14px",borderRadius:20,marginTop:8}}><span style={{fontSize:12,fontWeight:800,color:dDay<=3?"#DE350B":"#FF8B00"}}>D-{dDay===0?"DAY":dDay}</span><span style={{fontSize:12,color:"#172B4D",fontWeight:600}}>{upcoming.icon} {upcoming.title}</span></div>);})()}
      </div>
      <div style={{display:"flex",alignItems:"center",gap:8}}>
        <button onClick={prevM} style={{width:36,height:36,borderRadius:"50%",border:"1px solid #dfe1e6",background:"#fff",cursor:"pointer",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}} onMouseEnter={e=>{e.currentTarget.style.background="#deebff"}} onMouseLeave={e=>{e.currentTarget.style.background="#fff"}}>←</button>
        <div style={{fontSize:15,fontWeight:700,color:"#fff",background:"#0747A6",padding:"6px 20px",borderRadius:20,minWidth:120,textAlign:"center"}}>{calYear}년 {calMonth}월</div>
        <button onClick={nextM} style={{width:36,height:36,borderRadius:"50%",border:"1px solid #dfe1e6",background:"#fff",cursor:"pointer",fontSize:16,display:"flex",alignItems:"center",justifyContent:"center"}} onMouseEnter={e=>{e.currentTarget.style.background="#deebff"}} onMouseLeave={e=>{e.currentTarget.style.background="#fff"}}>→</button>
        {!isThis&&<button onClick={()=>{setCalMonth(new Date().getMonth()+1);setCalYear(new Date().getFullYear())}} style={{fontSize:12,color:"#0747A6",background:"#deebff",border:"none",borderRadius:12,padding:"6px 12px",cursor:"pointer",fontWeight:600}}>오늘</button>}
      </div>
    </div>
    <div style={{display:"flex",gap:6,marginBottom:16,overflowX:"auto",paddingBottom:4}}>{[{id:"all",label:"전체",color:"#172B4D"},{id:"tax",label:"🇰🇷 세금·납부",color:"#0747A6"},{id:"korea",label:"🏛️ 한국 경제",color:"#00875A"},{id:"global",label:"🇺🇸 미국·글로벌",color:"#6554C0"}].map(f=>(<button key={f.id} onClick={()=>setFilter(f.id)} style={{padding:"6px 14px",borderRadius:20,border:filter===f.id?"none":"1px solid #dfe1e6",fontSize:12,fontWeight:600,cursor:"pointer",flexShrink:0,background:filter===f.id?f.color:"#fff",color:filter===f.id?"#fff":f.color}}>{f.label}</button>))}</div>
    <div style={{background:"#fff",borderRadius:16,border:"1px solid #dfe1e6",overflow:"hidden"}}>
      <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",background:"#f8f9fc",borderBottom:"1px solid #dfe1e6"}}>{["일","월","화","수","목","금","토"].map((d,i)=>(<div key={d} style={{padding:"10px 4px",textAlign:"center",fontSize:12,fontWeight:700,color:i===0?"#DE350B":i===6?"#0747A6":"#6b778c"}}>{d}</div>))}</div>
      {weeks.map((wk,wi)=>(<div key={wi} style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",borderBottom:wi<weeks.length-1?"1px solid #f4f5f7":"none"}}>{wk.map((cell,ci)=>{if(!cell)return<div key={ci} style={{minHeight:isMo?60:80,background:"#fafafa"}}/>;const isT=isThis&&cell.day===today;return(<div key={ci} style={{minHeight:isMo?60:80,padding:isMo?"4px":"6px 8px",borderRight:ci<6?"1px solid #f4f5f7":"none",background:isT?"#deebff":"#fff"}}>
        <div style={{fontSize:isMo?11:13,fontWeight:isT?800:500,marginBottom:4,color:isT?"#0747A6":ci===0?"#DE350B":ci===6?"#0747A6":"#172B4D"}}>{cell.day}{isT&&<span style={{fontSize:9,background:"#0747A6",color:"#fff",borderRadius:4,padding:"1px 4px",marginLeft:4}}>오늘</span>}</div>
        {cell.events.slice(0,isMo?2:3).map((ev,ei)=>(<div key={ei} onClick={()=>{if(ev.calcCat){setCat(ev.calcCat);setCalc(ev.calcId);setPage("calc")}}} style={{fontSize:isMo?9:11,padding:isMo?"1px 3px":"2px 6px",marginBottom:2,borderRadius:4,background:(ev.urgent?ev.color+"20":ev.color+"10"),color:ev.color,fontWeight:ev.urgent?700:500,cursor:ev.calcCat?"pointer":"default",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",borderLeft:ev.urgent?"2px solid "+ev.color:"none"}}>{isMo?ev.icon:ev.icon+" "+ev.title}</div>))}
        {cell.events.length>(isMo?2:3)&&<div style={{fontSize:9,color:"#6b778c",textAlign:"center"}}>+{cell.events.length-(isMo?2:3)}</div>}
      </div>);})}</div>))}
    </div>
    <div style={{display:"grid",gridTemplateColumns:isMo?"1fr":"1fr 1fr",gap:16,marginTop:20}}>
      <div style={{background:"#fff",borderRadius:12,border:"1px solid #dfe1e6",padding:20}}>
        <div style={{fontSize:14,fontWeight:700,color:"#DE350B",marginBottom:12}}>⚠️ 이번 달 마감 주의</div>
        {filtered.filter(e=>e.urgent).map((ev,i)=>(<div key={i} onClick={()=>{if(ev.calcCat){setCat(ev.calcCat);setCalc(ev.calcId);setPage("calc")}}} style={{display:"flex",gap:10,padding:"10px 12px",marginBottom:6,borderRadius:8,background:"#fff8f0",border:"1px solid #FFE0B2",cursor:ev.calcCat?"pointer":"default"}} onMouseEnter={e=>{if(ev.calcCat)e.currentTarget.style.background="#deebff"}} onMouseLeave={e=>{e.currentTarget.style.background="#fff8f0"}}><span style={{fontSize:16}}>{ev.icon}</span><div><div style={{fontSize:13,fontWeight:700,color:"#172B4D"}}>{ev.title}</div><div style={{fontSize:11,color:"#0747A6",fontWeight:600}}>{calMonth}/{ev.day}{ev.end?"~"+calMonth+"/"+ev.end:""}</div></div>{ev.calcCat&&<span style={{fontSize:11,color:"#0747A6",marginLeft:"auto",alignSelf:"center"}}>계산→</span>}</div>))}
        {filtered.filter(e=>e.urgent).length===0&&<div style={{fontSize:13,color:"#6b778c"}}>이번 달 긴급 일정이 없습니다.</div>}
      </div>
      <div style={{background:"#fff",borderRadius:12,border:"1px solid #dfe1e6",padding:20}}>
        <div style={{fontSize:14,fontWeight:700,color:"#172B4D",marginBottom:12}}>📌 범례</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:16}}>{[{color:"#0747A6",label:"세금·납부"},{color:"#00875A",label:"한국 경제지표"},{color:"#6554C0",label:"미국·글로벌"},{color:"#DE350B",label:"마감 주의"}].map(l=>(<div key={l.label} style={{display:"flex",alignItems:"center",gap:6}}><div style={{width:10,height:10,borderRadius:3,background:l.color}}/><span style={{fontSize:12,color:"#6b778c"}}>{l.label}</span></div>))}</div>
        <div style={{padding:"14px 16px",background:"#f8f9fc",borderRadius:10}}><div style={{fontSize:13,fontWeight:700,color:"#172B4D",marginBottom:6}}>💡 {calMonth}월 경제 포인트</div><div style={{fontSize:12,color:"#6b778c",lineHeight:1.6}}>{liveData?.monthlyTips?.[String(calMonth)]||"매월 원천세 신고·납부와 주요 경제지표 발표일을 확인하세요."}</div></div>
      </div>
    </div>
  </div>);
}

function Skeleton({width="100%",height=20,borderRadius=6}){
  return<div style={{width,height,borderRadius,background:"linear-gradient(90deg,#f0f0f0 25%,#e0e0e0 50%,#f0f0f0 75%)",backgroundSize:"200% 100%",animation:"shimmer 1.5s infinite"}}/>;
}

function IndicatorTicker({liveData}){
  const items=liveData?.indicators?.items;if(!items||items.length===0)return null;
  return(<div style={{background:"#0d1117",overflow:"hidden",height:32,display:"flex",alignItems:"center"}}>
    <div style={{display:"flex",gap:32,animation:"ticker 30s linear infinite",whiteSpace:"nowrap",paddingLeft:16}}>
      {[...items,...items].map((ind,i)=>{const up=ind.change>0,dn=ind.change<0;return(<span key={i} style={{fontSize:12,color:"#e6edf3",display:"inline-flex",alignItems:"center",gap:6}}>
        <span style={{color:"#8b949e"}}>{ind.name}</span>
        <span style={{fontWeight:700,fontVariantNumeric:"tabular-nums"}}>{ind.current?.toLocaleString()}{ind.unit}</span>
        <span style={{color:up?"#FF5630":dn?"#36B37E":"#6b778c",fontWeight:600,fontSize:11}}>{up?"▲":dn?"▼":"—"}{Math.abs(ind.change)}{ind.unit}</span>
      </span>);})}
    </div>
    <style>{`@keyframes ticker{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}`}</style>
  </div>);
}

function Sparkline({data,color,w=60,h=24}){
  if(!data||data.length<2)return null;
  const min=Math.min(...data),max=Math.max(...data),range=max-min||1;
  const points=data.map((v,i)=>((i/(data.length-1))*w)+","+(h-((v-min)/range)*h)).join(' ');
  return<svg viewBox={`0 0 ${w} ${h}`} style={{width:w,height:h,display:"block",marginTop:6}}><polyline points={points} fill="none" stroke={color} strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"/></svg>;
}

function IndicatorDashboard({liveData,isMo}){
  const[selectedId,setSelectedId]=useState("baseRate");const[period,setPeriod]=useState("monthly");
  const indicators=liveData?.indicators?.items||[];const selected=indicators.find(i=>i.id===selectedId)||indicators[0];
  if(!selected)return null;
  const data=selected.history?.[period]||[];const labels=selected.history?.labels?.[period]||[];
  const maxVal=Math.max(...data);const minVal=Math.min(...data);const range=maxVal-minVal||1;
  const w=600,h=200,px=40,py=20,cW=w-px*2,cH=h-py*2;
  const points=data.map((v,i)=>`${px+(i/(data.length-1||1))*cW},${py+cH-(((v-minVal)/range)*cH)}`).join(' ');
  const isUp=selected.change>0,isDn=selected.change<0,cc=isUp?"#DE350B":isDn?"#00875A":"#6b778c";
  return(<div style={{maxWidth:1100,margin:"0 auto",padding:"48px 24px"}}>
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:24,flexWrap:"wrap",gap:8}}>
      <div><h2 style={{fontSize:isMo?20:24,fontWeight:800,color:"#172B4D",margin:"0 0 4px"}}>주요 경제지표</h2><p style={{fontSize:13,color:"#6b778c",margin:0}}>매일 자동 업데이트 · {liveData?.indicators?.lastUpdate||''} 기준</p></div>
    </div>
    <div style={{display:"flex",gap:12,overflowX:"auto",paddingBottom:12,WebkitOverflowScrolling:"touch",scrollbarWidth:"none"}}>
      {indicators.map(ind=>{const up=ind.change>0,dn=ind.change<0,ic=up?"#DE350B":dn?"#00875A":"#6b778c",act=selectedId===ind.id;return(
        <div key={ind.id} onClick={()=>setSelectedId(ind.id)} style={{minWidth:isMo?140:160,padding:"16px 18px",borderRadius:14,background:act?"linear-gradient(135deg,#0747A6,#0065FF)":"#fff",border:act?"none":"1px solid #dfe1e6",cursor:"pointer",flexShrink:0,transition:"all .2s"}}>
          <div style={{fontSize:11,color:act?"rgba(255,255,255,.7)":"#6b778c",fontWeight:600,marginBottom:6}}>{ind.name}</div>
          <div style={{fontSize:20,fontWeight:800,color:act?"#fff":"#172B4D"}}>{ind.current!==null?(ind.id==="usdkrw"?Math.round(ind.current).toLocaleString():ind.current.toLocaleString()):"확인 중"}{ind.current!==null&&ind.unit&&<span style={{fontSize:12,fontWeight:500}}>{ind.unit}</span>}</div>
          <div style={{fontSize:12,fontWeight:600,color:act?(up?"#FF5630":"#57D9A3"):ic,marginTop:4}}>{up?"▲":dn?"▼":"—"} {Math.abs(ind.change).toLocaleString()}{ind.unit}</div>
          <Sparkline data={ind.history?.daily||[]} color={act?"rgba(255,255,255,0.6)":up?"#DE350B":"#00875A"}/>
        </div>);})}
    </div>
    <div style={{background:"#fff",borderRadius:16,border:"1px solid #dfe1e6",padding:isMo?16:24,marginTop:16}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:20,flexWrap:"wrap",gap:8}}>
        <div style={{fontSize:16,fontWeight:700,color:"#172B4D"}}>{selected.name} <span style={{fontSize:13,fontWeight:500,color:"#6b778c"}}>({period==="daily"?"일별":period==="monthly"?"월별":"연도별"})</span></div>
        <div style={{display:"flex",gap:4,background:"#f4f5f7",borderRadius:8,padding:3}}>{[{id:"daily",l:"1주"},{id:"monthly",l:"1년"},{id:"yearly",l:"연도별"}].map(p=>(<button key={p.id} onClick={()=>setPeriod(p.id)} style={{padding:"6px 14px",borderRadius:6,border:"none",fontSize:12,fontWeight:600,cursor:"pointer",background:period===p.id?"#fff":"transparent",color:period===p.id?"#0747A6":"#6b778c",boxShadow:period===p.id?"0 1px 3px rgba(0,0,0,.1)":"none"}}>{p.l}</button>))}</div>
      </div>
      <div style={{width:"100%",overflowX:"auto"}}>
        <svg viewBox={`0 0 ${w} ${h+30}`} style={{width:"100%",minWidth:isMo?400:undefined,height:isMo?200:250}}>
          {[0,.25,.5,.75,1].map((r,i)=>{const y=py+cH*(1-r);return<g key={i}><line x1={px} y1={y} x2={w-px} y2={y} stroke="#f4f5f7" strokeWidth="1"/><text x={px-8} y={y+4} textAnchor="end" fontSize="10" fill="#a5adba">{(minVal+range*r).toFixed(selected.unit==="%"?2:0)}</text></g>;})}
          <defs><linearGradient id="areaGrad" x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor="#0747A6"/><stop offset="100%" stopColor="#0747A6" stopOpacity="0"/></linearGradient></defs>
          <polygon points={`${px},${py+cH} ${points} ${px+((data.length-1)/(data.length-1||1))*cW},${py+cH}`} fill="url(#areaGrad)" opacity=".15"/>
          <polyline points={points} fill="none" stroke="#0747A6" strokeWidth="2.5" strokeLinejoin="round" strokeLinecap="round"/>
          {data.map((v,i)=>{const x=px+(i/(data.length-1||1))*cW,y=py+cH-(((v-minVal)/range)*cH);return<g key={i}><circle cx={x} cy={y} r={i===data.length-1?5:3} fill={i===data.length-1?"#0747A6":"#fff"} stroke="#0747A6" strokeWidth="2"/>{i===data.length-1&&<text x={x} y={y-12} textAnchor="middle" fontSize="12" fontWeight="700" fill="#0747A6">{v.toLocaleString()}{selected.unit}</text>}</g>;})}
          {labels.map((l,i)=>{const x=px+(i/(labels.length-1||1))*cW;return(labels.length<=8||i%Math.ceil(labels.length/8)===0||i===labels.length-1)?<text key={i} x={x} y={h+15} textAnchor="middle" fontSize="10" fill="#a5adba">{l}</text>:null;})}
        </svg>
      </div>
      <div style={{display:"grid",gridTemplateColumns:isMo?"repeat(2,1fr)":"repeat(4,1fr)",gap:12,marginTop:16,paddingTop:16,borderTop:"1px solid #f4f5f7"}}>
        <div><div style={{fontSize:11,color:"#6b778c"}}>현재</div><div style={{fontSize:16,fontWeight:700,color:"#172B4D"}}>{selected.current.toLocaleString()}{selected.unit}</div></div>
        <div><div style={{fontSize:11,color:"#6b778c"}}>전일 대비</div><div style={{fontSize:16,fontWeight:700,color:cc}}>{isUp?"▲":isDn?"▼":"—"} {Math.abs(selected.change).toLocaleString()}{selected.unit}</div></div>
        <div><div style={{fontSize:11,color:"#6b778c"}}>기간 최고</div><div style={{fontSize:16,fontWeight:700,color:"#172B4D"}}>{maxVal.toLocaleString()}{selected.unit}</div></div>
        <div><div style={{fontSize:11,color:"#6b778c"}}>기간 최저</div><div style={{fontSize:16,fontWeight:700,color:"#172B4D"}}>{minVal.toLocaleString()}{selected.unit}</div></div>
      </div>
    </div>
    <div style={{fontSize:11,color:"#a5adba",marginTop:8,textAlign:"right"}}>출처: 한국은행, 한국거래소, 한국부동산원, 통계청 | 매일 자동 업데이트</div>
  </div>);
}

function AccItem({title,defaultOpen,children}){
  const[open,setOpen]=useState(defaultOpen||false);
  return (<div style={{marginBottom:8}}>
    <button onClick={()=>setOpen(!open)}
      style={{width:"100%",padding:"12px 16px",background:"#fff",border:`1px solid ${P.bd}`,borderRadius:open?"12px 12px 0 0":12,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"space-between",fontFamily:"inherit"}}>
      <span style={{fontSize:14,fontWeight:600,color:P.tx}}>{title}</span>
      <span style={{transform:open?"rotate(180deg)":"none",transition:"transform .2s",display:"inline-block",color:P.mt,fontSize:12}}>▼</span>
    </button>
    {open&&<div style={{padding:"12px 16px 16px",background:"#fff",border:`1px solid ${P.bd}`,borderTop:"none",borderRadius:"0 0 12px 12px"}}>{children}</div>}
  </div>);
}
